// service-worker.js

const STATIC_CACHE_NAME = 'qran-top-static-v10'; // Version bump to force update
const DATA_CACHE_NAME = 'qran-top-data-v8'; // Version bump to force update

// Core data files that are essential for the app to work offline.
const CORE_DATA_URLS = [
  'https://storage.googleapis.com/qurantxt/quran-simple-clean.json',
  'https://storage.googleapis.com/qurantxt/quran-uthmani.json',
];

// The "app shell" - minimal files needed for the UI to render.
const STATIC_FILES_TO_CACHE = [
  './',
  './index.html',
  './index.tsx',
  './index.css',
  './Uthman.ttf',
  './manifest.json',
  './thumbnail.png',
  // Note: aistudio-host.js is not included as it's injected and managed by the environment.
];

// Install event: cache static assets and core data.
self.addEventListener('install', event => {
  console.log('[Service Worker] Install');
  event.waitUntil(
    Promise.all([
      caches.open(STATIC_CACHE_NAME).then(cache => {
        console.log('[Service Worker] Pre-caching static app shell');
        // Use ignoreSearch to cache the base file without query parameters if needed, though addAll is direct.
        const requests = STATIC_FILES_TO_CACHE.map(url => new Request(url, { cache: 'reload' }));
        return cache.addAll(requests);
      }),
      caches.open(DATA_CACHE_NAME).then(cache => {
        console.log('[Service Worker] Pre-caching core Quran data');
        const requests = CORE_DATA_URLS.map(url => new Request(url, { cache: 'reload' }));
        return cache.addAll(requests);
      })
    ]).then(() => {
        console.log('[Service Worker] Installation complete. Activating immediately.');
        return self.skipWaiting();
    })
  );
});

// Activate event: clean up old caches.
self.addEventListener('activate', event => {
  console.log('[Service Worker] Activate');
  const cacheWhitelist = [STATIC_CACHE_NAME, DATA_CACHE_NAME];
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            console.log('[Service Worker] Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    }).then(() => {
        console.log('[Service Worker] Activation complete. Claiming clients.');
        return self.clients.claim();
    })
  );
});

// Fetch event: handle network requests with different strategies.
self.addEventListener('fetch', event => {
  const { request } = event;

  // Defensive check: The URL constructor can fail on non-standard schemes
  // like 'chrome-extension://' or 'about:blank'. We only want to handle http/https requests.
  if (!request.url.startsWith('http')) {
    return;
  }

  const url = new URL(request.url);

  // Ignore requests that are not GET.
  if (request.method !== 'GET') {
    return;
  }

  // Ignore requests to Firebase, as it has its own offline persistence mechanism.
  if (url.hostname.includes('firebase') || url.hostname.includes('googleapis.com')) {
    // Exception: Allow our GCS bucket for Quran data
    if (url.hostname !== 'storage.googleapis.com' || !url.pathname.startsWith('/qurantxt/')) {
        return;
    }
  }

  // Strategy 1: Stale-While-Revalidate for API calls (data).
  // This serves the cached version immediately for speed, then updates the cache in the background.
  if (url.hostname === 'storage.googleapis.com' || url.hostname === 'api.alquran.cloud' || url.hostname === 'cdn.jsdelivr.net' || url.hostname === 'everyayah.com' || url.hostname === 'cdn.islamic.network') {
    event.respondWith(
      caches.open(DATA_CACHE_NAME).then(cache => {
        return cache.match(request).then(cachedResponse => {
          const fetchPromise = fetch(request).then(networkResponse => {
            // Check if we received a valid response before caching
            if (networkResponse && networkResponse.status === 200) {
              cache.put(request, networkResponse.clone());
            }
            return networkResponse;
          }).catch(err => {
            // Network fetch failed, which is expected offline.
            // The cachedResponse will be used if it exists.
            console.warn('[Service Worker] Network fetch failed for:', request.url);
          });

          return cachedResponse || fetchPromise;
        });
      })
    );
    return; // End execution for this strategy
  }

  // Strategy 2: Cache First for static assets (app shell).
  // This is ideal for files that don't change often.
  // We use ignoreSearch: true to ensure cache-busting parameters don't prevent cache hits.
  event.respondWith(
    caches.match(request, { ignoreSearch: true }).then(cachedResponse => {
      if (cachedResponse) {
        return cachedResponse;
      }
      // If not in cache, fetch from network.
      return fetch(request).then(networkResponse => {
        // Optional: Cache newly fetched static assets if needed, but primary caching is on install.
        return networkResponse;
      });
    })
  );
});

// Listen for a message from the client to activate the new service worker.
self.addEventListener('message', event => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { db } from '../firebase';
import { SpinnerIcon, UsersIcon, PlusIcon, CopyIcon, CheckIcon, ClearIcon, TrashIcon, ShieldCheckIcon } from './icons';

// --- Types ---
interface JuzStatus {
    status: 'available' | 'reserved' | 'completed';
    by?: string;
    reservedAt?: any; // Firestore Timestamp
    completedAt?: any; // Firestore Timestamp
}

interface Khatmah {
    id: string;
    name: string;
    createdAt: any; // Firestore Timestamp
    juz_status: { [key: number]: JuzStatus };
    visibility: 'public' | 'private';
}

interface KhatmahHistoryItem {
    id: string;
    name: string;
}

const KHATMIYAH_HISTORY_KEY = 'qran_khatmiyah_history';
const KHATMIYAH_ACTION_TRACKER_KEY = 'qran_khatmiyah_actions_v1';

// --- Helper Functions ---
const generateKhatmahId = (): string => {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const nums = '0123456789';
    let letters = '';
    for (let i = 0; i < 3; i++) {
        letters += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    let numbers = '';
    for (let i = 0; i < 3; i++) {
        numbers += nums.charAt(Math.floor(Math.random() * nums.length));
    }
    return `${letters}${numbers}`;
};

// Anti-spam helper functions
const getActionTracker = () => {
    const today = new Date().toISOString().split('T')[0];
    try {
        const stored = localStorage.getItem(KHATMIYAH_ACTION_TRACKER_KEY);
        if (stored) {
            const tracker = JSON.parse(stored);
            if (tracker.date === today) {
                return tracker;
            }
        }
    } catch (e) { console.error("Could not parse action tracker", e); }
    // If no tracker, or it's for a previous day, reset it
    return { date: today, creations: 0, reservations: 0, completions: 0 };
};

const checkActionLimit = (actionType: 'creations' | 'reservations' | 'completions'): boolean => {
    const tracker = getActionTracker();
    const limits = { creations: 1, reservations: 10, completions: 10 };

    if (tracker[actionType] >= limits[actionType]) {
        alert(`لقد وصلت إلى الحد الأقصى المسموح به لهذا الإجراء اليوم (${limits[actionType]}). يرجى المحاولة غداً.`);
        return false;
    }
    return true;
};

const incrementActionCount = (actionType: 'creations' | 'reservations' | 'completions') => {
    const tracker = getActionTracker();
    tracker[actionType] += 1;
    localStorage.setItem(KHATMIYAH_ACTION_TRACKER_KEY, JSON.stringify(tracker));
};


// --- Main Component ---
interface KhatmiyahViewProps {
    khatmiyahId: string | null;
}

const CreateKhatmahModal: React.FC<{onClose: () => void; onCreate: (name: string, visibility: 'public' | 'private') => Promise<void>}> = ({ onClose, onCreate }) => {
    const [name, setName] = useState('');
    const [visibility, setVisibility] = useState<'public' | 'private'>('public');
    const [isCreating, setIsCreating] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;
        setIsCreating(true);
        try {
            await onCreate(name, visibility);
        } catch (err) {
            // Error is handled in the parent
        } finally {
            setIsCreating(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
            <form onSubmit={handleSubmit} className="bg-surface rounded-lg shadow-xl w-full max-w-md" onClick={e => e.stopPropagation()}>
                <div className="p-5 border-b border-border-default">
                    <h2 className="text-xl font-bold">إنشاء ختمة جديدة</h2>
                </div>
                <div className="p-5 space-y-4">
                    <div>
                        <label htmlFor="khatmah-name" className="block text-sm font-medium mb-1">اسم الختمة</label>
                        <input id="khatmah-name" type="text" value={name} onChange={e => setName(e.target.value)} required placeholder="مثال: ختمة شهر رمضان" className="w-full p-2 border rounded bg-surface border-border-default" />
                    </div>
                    <div>
                         <label className="block text-sm font-medium mb-1">من يمكنه رؤيتها؟</label>
                         <div className="flex gap-4">
                            <label className="flex items-center gap-2 cursor-pointer"><input type="radio" name="visibility" value="public" checked={visibility === 'public'} onChange={() => setVisibility('public')} className="w-4 h-4 text-primary"/> عامة (تظهر للجميع)</label>
                            <label className="flex items-center gap-2 cursor-pointer"><input type="radio" name="visibility" value="private" checked={visibility === 'private'} onChange={() => setVisibility('private')} className="w-4 h-4 text-primary"/> خاصة (فقط لمن يملك الكود)</label>
                         </div>
                    </div>
                </div>
                <div className="p-4 bg-surface-subtle flex justify-end gap-3">
                    <button type="button" onClick={onClose} className="px-4 py-2 rounded">إلغاء</button>
                    <button type="submit" disabled={isCreating || !name.trim()} className="px-4 py-2 bg-primary text-white font-semibold rounded disabled:opacity-50 flex items-center gap-2">
                        {isCreating ? <SpinnerIcon className="w-5 h-5"/> : <PlusIcon className="w-5 h-5"/>}
                        {isCreating ? "جاري الإنشاء..." : "إنشاء"}
                    </button>
                </div>
            </form>
        </div>
    );
};

const JoinKhatmahModal: React.FC<{onClose: () => void; onJoin: (id: string) => void}> = ({ onClose, onJoin }) => {
    const [id, setId] = useState('');

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onJoin(id);
    };

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
            <form onSubmit={handleSubmit} className="bg-surface rounded-lg shadow-xl w-full max-w-md" onClick={e => e.stopPropagation()}>
                <div className="p-5 border-b border-border-default"><h2 className="text-xl font-bold">الانضمام إلى ختمة</h2></div>
                <div className="p-5">
                    <label htmlFor="khatmah-id" className="block text-sm font-medium mb-1">أدخل كود الختمة (6 رموز)</label>
                    <input id="khatmah-id" type="text" value={id} onChange={e => setId(e.target.value.toUpperCase())} required maxLength={6} className="w-full p-3 text-2xl font-mono tracking-widest text-center border rounded bg-surface border-border-default" />
                </div>
                <div className="p-4 bg-surface-subtle flex justify-end gap-3">
                    <button type="button" onClick={onClose} className="px-4 py-2 rounded">إلغاء</button>
                    <button type="submit" disabled={id.length !== 6} className="px-4 py-2 bg-primary text-white font-semibold rounded disabled:opacity-50">انضمام</button>
                </div>
            </form>
        </div>
    );
};

const ReserveJuzModal: React.FC<{onClose: () => void; onReserve: (name: string) => Promise<void>; juzNumber: number}> = ({ onClose, onReserve, juzNumber }) => {
    const [name, setName] = useState('');
    const [isReserving, setIsReserving] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;
        setIsReserving(true);
        try {
            await onReserve(name);
        } catch (err) {
            // Error handled by parent
        } finally {
            setIsReserving(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
            <form onSubmit={handleSubmit} className="bg-surface rounded-lg shadow-xl w-full max-w-md" onClick={e => e.stopPropagation()}>
                <div className="p-5 border-b border-border-default"><h2 className="text-xl font-bold">حجز الجزء {juzNumber}</h2></div>
                <div className="p-5">
                    <label htmlFor="reserver-name" className="block text-sm font-medium mb-1">الاسم (سيظهر للجميع)</label>
                    <input id="reserver-name" type="text" value={name} onChange={e => setName(e.target.value)} required placeholder="اكتب اسمك هنا" className="w-full p-2 border rounded bg-surface border-border-default" />
                </div>
                <div className="p-4 bg-surface-subtle flex justify-end gap-3">
                    <button type="button" onClick={onClose} className="px-4 py-2 rounded">إلغاء</button>
                    <button type="submit" disabled={isReserving || !name.trim()} className="px-4 py-2 bg-primary text-white font-semibold rounded disabled:opacity-50 flex items-center gap-2">
                        {isReserving ? <SpinnerIcon className="w-5 h-5"/> : <CheckIcon className="w-5 h-5"/>}
                        {isReserving ? "جاري الحجز..." : "تأكيد الحجز"}
                    </button>
                </div>
            </form>
        </div>
    );
};

const KhatmiyahView: React.FC<KhatmiyahViewProps> = ({ khatmiyahId }) => {
    const [khatmah, setKhatmah] = useState<Khatmah | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [modal, setModal] = useState<'create' | 'join' | 'reserve' | null>(null);
    const [activeJuz, setActiveJuz] = useState<number | null>(null);
    const [updatingJuz, setUpdatingJuz] = useState<number | null>(null);

    const [publicKhatmahs, setPublicKhatmahs] = useState<Khatmah[]>([]);
    const [loadingPublic, setLoadingPublic] = useState(true);

    const [history, setHistory] = useState<KhatmahHistoryItem[]>(() => {
        try {
            const stored = localStorage.getItem(KHATMIYAH_HISTORY_KEY);
            return stored ? JSON.parse(stored) : [];
        } catch {
            return [];
        }
    });

    const addKhatmahToHistory = useCallback((khatmahToAdd: KhatmahHistoryItem) => {
        setHistory(prev => {
            const existing = prev.find(h => h.id === khatmahToAdd.id);
            const filtered = prev.filter(h => h.id !== khatmahToAdd.id);
            const updatedHistory = [{... (existing || {}), ...khatmahToAdd}, ...filtered];

            if (updatedHistory.length > 20) {
                updatedHistory.pop();
            }

            localStorage.setItem(KHATMIYAH_HISTORY_KEY, JSON.stringify(updatedHistory));
            return updatedHistory;
        });
    }, []);

    const removeKhatmahFromHistory = useCallback((idToRemove: string) => {
        if (window.confirm("هل تريد إزالة هذه الختمة من قائمتك؟ لن يتم حذف الختمة نفسها.")) {
            setHistory(prev => {
                const newHistory = prev.filter(h => h.id !== idToRemove);
                localStorage.setItem(KHATMIYAH_HISTORY_KEY, JSON.stringify(newHistory));
                return newHistory;
            });
        }
    }, []);

    // Fetch public Khatmahs for the home view
    useEffect(() => {
        if (khatmiyahId) {
            setLoadingPublic(false);
            return;
        }

        setLoadingPublic(true);
        const unsubscribe = db.collection('khatmahs')
            .orderBy('createdAt', 'desc')
            .limit(30)
            .onSnapshot(snapshot => {
                const allRecent = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Khatmah));
                const publicOnly = allRecent.filter(k => k.visibility === 'public');
                setPublicKhatmahs(publicOnly);
                // Note: Automatic deletion logic removed. This should be handled by a server-side function.
                setLoadingPublic(false);
            }, err => {
                console.error("Error fetching public khatmahs:", err);
                setError("فشل في تحميل الختمات العامة.");
                setLoadingPublic(false);
            });

        return () => unsubscribe();
    }, [khatmiyahId]);


    // Fetch specific Khatmah data
    useEffect(() => {
        if (!khatmiyahId) {
            setLoading(false);
            setError(null);
            setKhatmah(null);
            return;
        }

        setLoading(true);
        const unsubscribe = db.collection('khatmahs').doc(khatmiyahId)
            .onSnapshot(doc => {
                if (doc.exists) {
                    const data = doc.data() as Omit<Khatmah, 'id'>;
                    const loadedKhatmah = { id: doc.id, ...data };
                    setKhatmah(loadedKhatmah);
                    addKhatmahToHistory({ id: loadedKhatmah.id, name: loadedKhatmah.name });
                    setError(null);
                } else {
                    setError(`الختمة بالمعرف "${khatmiyahId}" غير موجودة. تأكد من صحة الرابط أو الكود.`);
                    setKhatmah(null);
                }
                setLoading(false);
            }, err => {
                console.error("Error fetching Khatmah:", err);
                setError("حدث خطأ أثناء تحميل بيانات الختمة.");
                setLoading(false);
            });

        return () => unsubscribe();
    }, [khatmiyahId, addKhatmahToHistory]);

    // --- Event Handlers ---
    const handleCreateKhatmah = async (name: string, visibility: 'public' | 'private') => {
        if (!checkActionLimit('creations')) {
            throw new Error("Creation limit reached.");
        }

        const initialJuzStatus: { [key: number]: JuzStatus } = {};
        for (let i = 1; i <= 30; i++) {
            initialJuzStatus[i] = { status: 'available' };
        }

        let newId = '';
        let docExists = true;
        let attempts = 0;

        while(docExists && attempts < 10) {
            newId = generateKhatmahId();
            const docRef = db.collection('khatmahs').doc(newId);
            const docSnap = await docRef.get();
            docExists = docSnap.exists;
            attempts++;
        }

        if (docExists) {
            alert("فشل في إنشاء معرف فريد للختمة، يرجى المحاولة مرة أخرى.");
            throw new Error("Could not generate a unique ID.");
        }

        try {
            await db.collection('khatmahs').doc(newId).set({
                name: name,
                visibility: visibility,
                createdAt: new Date(),
                juz_status: initialJuzStatus
            });

            incrementActionCount('creations');
            addKhatmahToHistory({id: newId, name});
            window.location.hash = `#/khatmiyah/${newId}`;
            setModal(null);
        } catch (err) {
            console.error("Error creating Khatmah:", err);
            alert("فشل إنشاء الختمة. يرجى المحاولة مرة أخرى.");
            throw err;
        }
    };

    const handleJoinKhatmah = (id: string) => {
        if (id.trim()) {
            window.location.hash = `#/khatmiyah/${id.trim()}`;
            setModal(null);
        }
    }

    const handleJuzClick = (juzNumber: number, status: JuzStatus) => {
        if (updatingJuz) return;

        if (status.status === 'available') {
            setActiveJuz(juzNumber);
            setModal('reserve');
        } else if (status.status === 'reserved') {
            if (window.confirm(`هل تريد تأكيد إتمام قراءة الجزء ${juzNumber}؟`)) {
                handleCompleteJuz(juzNumber);
            }
        }
    };

    const handleReserveJuz = async (juzNumber: number, name: string) => {
        if (!khatmiyahId || !name.trim()) return;

        if (!checkActionLimit('reservations')) {
            throw new Error("Reservation limit reached.");
        }

        setUpdatingJuz(juzNumber);
        const docRef = db.collection('khatmahs').doc(khatmiyahId);

        try {
            await db.runTransaction(async (transaction: any) => {
                const doc = await transaction.get(docRef);
                if (!doc.exists) throw new Error("Document does not exist!");

                const currentJuzStatus = doc.data().juz_status[juzNumber];
                if (currentJuzStatus.status !== 'available') {
                    throw new Error("This Juz has already been reserved.");
                }

                transaction.update(docRef, { 
                    [`juz_status.${juzNumber}`]: {
                        status: 'reserved',
                        by: name.trim(),
                        reservedAt: new Date()
                    }
                });
            });

            incrementActionCount('reservations');
            setModal(null);
            setActiveJuz(null);
        } catch (err) {
            console.error("Error reserving Juz:", err);
            if (!(err instanceof Error && err.message === "Reservation limit reached.")) {
                alert("فشل حجز الجزء. قد يكون شخص آخر قد حجزه قبلك.");
            }
            throw err;
        } finally {
            setUpdatingJuz(null);
        }
    };

    const handleCompleteJuz = async (juzNumber: number) => {
        if (!khatmiyahId) return;

        if (!checkActionLimit('completions')) {
            return;
        }

        setUpdatingJuz(juzNumber);
        const docRef = db.collection('khatmahs').doc(khatmiyahId);

        try {
            await db.runTransaction(async (transaction: any) => {
                const doc = await transaction.get(docRef);
                if (!doc.exists) throw new Error("Document does not exist!");

                const currentJuzStatus = doc.data().juz_status[juzNumber];
                if (currentJuzStatus.status !== 'reserved') {
                    throw new Error("This Juz is not currently reserved.");
                }

                transaction.update(docRef, {
                    [`juz_status.${juzNumber}`]: {
                        ...currentJuzStatus,
                        status: 'completed',
                        completedAt: new Date(),
                    }
                });
            });
            incrementActionCount('completions');
        } catch (err) {
            console.error("Error completing Juz:", err);
            if (!(err instanceof Error && err.message === "Completion limit reached.")) {
                alert("فشل تحديث حالة الجزء. قد يكون هناك مشكلة في الاتصال.");
            }
        } finally {
            setUpdatingJuz(null);
        }
    };

    // --- UI Rendering ---

    const progress = useMemo(() => {
        if (!khatmah) return 0;
        const completedCount = Object.values(khatmah.juz_status).filter(s => s.status === 'completed').length;
        return Math.round((completedCount / 30) * 100);
    }, [khatmah]);

    if (loading) {
        return <div className="flex justify-center p-16"><SpinnerIcon className="w-12 h-12 text-primary" /></div>;
    }

    if (error) {
        return (
            <div className="text-center p-10 bg-surface rounded-lg shadow-md max-w-lg mx-auto">
                <p className="text-red-500 font-semibold">{error}</p>
                <button onClick={() => window.location.hash = '#/khatmiyah'} className="mt-4 px-4 py-2 bg-primary text-white rounded-md">
                    العودة إلى الصفحة الرئيسية للختميات
                </button>
            </div>
        );
    }

    if (khatmah) {
        // --- Detailed Khatmah View ---
        return (
            <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
                {modal === 'reserve' && activeJuz && (
                    <ReserveJuzModal
                        onClose={() => { setModal(null); setActiveJuz(null); }}
                        onReserve={(name) => handleReserveJuz(activeJuz, name)}
                        juzNumber={activeJuz}
                    />
                )}
                <header className="mb-6 text-center">
                    <h1 className="text-3xl font-bold text-primary-text-strong mb-2">{khatmah.name}</h1>
                    <div className="w-full bg-surface-subtle rounded-full h-4 border border-border-default">
                        <div
                            className="bg-green-500 h-4 rounded-full text-xs font-medium text-white text-center p-0.5 leading-none transition-all duration-500"
                            style={{ width: `${progress}%` }}
                        >
                            {progress > 10 && `${progress}%`}
                        </div>
                    </div>
                     <p className="text-sm text-text-muted mt-2">
                        {progress < 100 ? `${30 - Object.values(khatmah.juz_status).filter(s => s.status === 'completed').length} جزء متبقي` : "اكتملت الختمة، تقبل الله منكم."}
                    </p>
                </header>

                <main>
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-3">
                        {Object.entries(khatmah.juz_status).map(([juzNumStr, status]) => {
                            const juzNumber = parseInt(juzNumStr, 10);
                            let statusClass = '';
                            let statusText = 'متاح';
                            switch (status.status) {
                                case 'reserved':
                                    statusClass = 'bg-yellow-100 dark:bg-yellow-900/40 border-yellow-400 text-yellow-800 dark:text-yellow-200 cursor-pointer hover:bg-yellow-200 dark:hover:bg-yellow-900/60';
                                    statusText = `محجوز (${status.by})`;
                                    break;
                                case 'completed':
                                    statusClass = 'bg-green-100 dark:bg-green-900/40 border-green-500 text-green-800 dark:text-green-300 cursor-default opacity-80';
                                    statusText = `مكتمل (${status.by})`;
                                    break;
                                default:
                                    statusClass = 'bg-surface-subtle border-border-default text-text-secondary cursor-pointer hover:bg-surface-hover hover:border-primary';
                                    break;
                            }

                            return (
                                <button
                                    key={juzNumber}
                                    onClick={() => handleJuzClick(juzNumber, status)}
                                    disabled={status.status === 'completed' || !!updatingJuz}
                                    className={`p-4 rounded-lg border-2 text-center transition-colors relative ${statusClass}`}
                                >
                                    {updatingJuz === juzNumber && <div className="absolute inset-0 bg-white/50 dark:bg-black/50 flex items-center justify-center rounded-lg"><SpinnerIcon className="w-6 h-6"/></div>}
                                    <span className="block text-2xl font-bold">{juzNumber}</span>
                                    <span className="block text-xs truncate">{statusText}</span>
                                </button>
                            );
                        })}
                    </div>
                </main>
            </div>
        );
    }

    // --- Home View ---
    return (
        <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
             {modal === 'create' && <CreateKhatmahModal onClose={() => setModal(null)} onCreate={handleCreateKhatmah} />}
             {modal === 'join' && <JoinKhatmahModal onClose={() => setModal(null)} onJoin={handleJoinKhatmah} />}

             <header className="text-center mb-8">
                <UsersIcon className="w-16 h-16 mx-auto text-primary mb-2"/>
                <h1 className="text-3xl font-bold text-primary-text-strong">الختمة الجماعية</h1>
                <p className="text-text-secondary mt-2">شارك في ختم القرآن الكريم مع الآخرين، أو أنشئ ختمة جديدة وادعُ أصدقاءك.</p>
            </header>

            <div className="flex flex-col sm:flex-row gap-4 mb-10">
                <button onClick={() => setModal('create')} className="flex-1 flex items-center justify-center gap-3 px-6 py-4 bg-primary text-white font-bold rounded-lg hover:bg-primary-hover transition-all duration-200 shadow-md hover:shadow-lg">
                    <PlusIcon className="w-6 h-6"/>
                    <span>إنشاء ختمة جديدة</span>
                </button>
                 <button onClick={() => setModal('join')} className="flex-1 flex items-center justify-center gap-3 px-6 py-4 bg-surface-subtle text-text-primary font-bold rounded-lg hover:bg-surface-hover transition-all duration-200 shadow-sm hover:shadow-md border border-border-default">
                    <span>الانضمام بـ "كود"</span>
                </button>
            </div>

            <div className="space-y-8">
                {history.length > 0 && (
                    <section>
                        <h2 className="text-xl font-semibold mb-4 text-text-primary">ختماتك السابقة</h2>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                            {history.map(item => (
                                <div key={item.id} className="group relative">
                                    <a href={`#/khatmiyah/${item.id}`} onClick={(e) => {e.preventDefault(); window.location.hash = `#/khatmiyah/${item.id}`;}} className="block w-full p-4 bg-surface rounded-lg shadow-sm border border-border-default hover:shadow-md hover:border-primary transition-all">
