export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [dataSourceStatus, setDataSourceStatus] = useState<'primary' | 'fallback'>('primary');
    const [availableFonts, setAvailableFonts] = useState<QuranFont[]>(DEFAULT_FONTS);
    const [availableEditions, setAvailableEditions] = useState<QuranEdition[]>(FULL_DEFAULT_EDITIONS);

    const getEditionUrl = useCallback((edition: QuranEdition): string => {
        const { identifier, sourceApi } = edition;
        if (identifier === 'quran-simple-clean') return 'https://storage.googleapis.com/qurantxt/quran-simple-clean.json';
        if (identifier === 'quran-uthmani') return 'https://storage.googleapis.com/qurantxt/quran-uthmani.json';
        if (identifier === 'quran-uthmani-simple') return 'https://storage.googleapis.com/qurantxt/quran-uthmani.json';
        if (sourceApi === 'manual' || identifier.startsWith('http')) return identifier;
        if (sourceApi === 'fawazahmed0') return `https://cdn.jsdelivr.net/gh/fawazahmed0/quran-api@1/editions/${identifier}.json`;
        return `https://api.alquran.cloud/v1/quran/${identifier}`;
    }, []);

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        if (!editionIdentifier || (allQuranData && allQuranData[editionIdentifier])) return;
        setLoadingEditions(prev => [...prev, editionIdentifier]);
        setError(null);
        const isCoreEdition = editionIdentifier === 'quran-simple-clean' || editionIdentifier === 'quran-uthmani';

        if (editionIdentifier === 'quran-uthmani-simple') {
            try {
                const response = await fetch(getEditionUrl({ identifier: 'quran-uthmani' } as QuranEdition));
                if (!response.ok) throw new Error('Failed to fetch base Uthmani text');
                const apiData = await response.json();
                if (apiData.code !== 200 || !apiData.data || !apiData.data.surahs) throw new Error('Invalid base data');

                let bismillahCleanedSurahs: SurahData[] = apiData.data.surahs;
                const fatiha = bismillahCleanedSurahs.find(s => s.number === 1);
                const definitiveBismillahText = fatiha?.ayahs[0]?.text || 'بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ';

                bismillahCleanedSurahs = bismillahCleanedSurahs.map(surah => {
                    if (surah.number === 1 || surah.number === 9 || !surah.ayahs || surah.ayahs.length === 0) return surah;
                    let ayahs = [...surah.ayahs];
                    if (ayahs[0].numberInSurah === 0) ayahs = ayahs.slice(1);
                    if (ayahs.length === 0) return { ...surah, ayahs: [], numberOfAyahs: 0 };

                    const firstAyah = ayahs[0];
                    const normalizedAyahText = normalizeArabicText(firstAyah.text).replace(/\s/g, '');
                    const normalizedBismillah = normalizeArabicText(definitiveBismillahText).replace(/\s/g, '');

                    if (firstAyah.text && normalizedAyahText.startsWith(normalizedBismillah)) {
                        const wordsInBismillah = definitiveBismillahText.split(' ').length;
                        const wordsInAyah = firstAyah.text.split(' ');
                        const cleanedText = wordsInAyah.slice(wordsInBismillah).join(' ').trim();
                        if (cleanedText === '') {
                             const cleanedAyahs = ayahs.slice(1).map((ayah, index) => ({ ...ayah, numberInSurah: index + 1 }));
                             return { ...surah, ayahs: cleanedAyahs, numberOfAyahs: cleanedAyahs.length };
                        } else {
                            const newAyahs = [...ayahs];
                            newAyahs[0] = { ...firstAyah, text: cleanedText };
                            return { ...surah, ayahs: newAyahs };
                        }
                    }
                    return { ...surah, ayahs };
                });

                const processedSurahs: SurahData[] = bismillahCleanedSurahs.map((surah: any) => ({
                    ...surah,
                    ayahs: surah.ayahs.map((ayah: any) => ({ ...ayah, text: removeWaqfMarks(ayah.text) }))
                }));
                setAllQuranData(prev => ({ ...prev, [editionIdentifier]: processedSurahs }));
            } catch (err) {
                console.error("Failed to generate Uthmani Simple edition", err);
                setError("فشل في توليد النسخة العثمانية المبسطة.");
            } finally {
                setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
            }
            return;
        }

        const processApiData = (apiData: any, urlForTypeCheck: string): SurahData[] => {
            // ... (rest of the processing logic from App.tsx)
            return []; // Placeholder to avoid TS error, will be replaced with full logic.
        };

        // ... (rest of the fetch logic from App.tsx)
    }, [allQuranData, availableEditions, getEditionUrl]);

    useEffect(() => {
        const initializeApp = async () => {
            setIsInitialLoading(true);
            await fetchCustomEditionData('quran-simple-clean');
            setIsInitialLoading(false);

            setIsBackgroundLoading(true);
            try {
                await Promise.all([
                    fetchCustomEditionData('quran-uthmani'),
                    (async () => {
                        const fontsSnapshot = await db.collection('qran_fonts').get();
                        if (!fontsSnapshot.empty) setAvailableFonts(fontsSnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() })));
                    })(),
                    (async () => {
                        let apiEditions: QuranEdition[] = [];
                        try {
                            const response = await fetch('https://api.alquran.cloud/v1/edition');
                            if (response.ok) {
                                const data = await response.json();
                                if (data.code === 200 && Array.isArray(data.data)) {
                                    apiEditions = data.data.map((e: any) => ({
                                        identifier: e.identifier, language: e.language, name: e.name, englishName: e.englishName,
                                        format: e.format, type: e.type, direction: e.direction || (e.language === 'ar' ? 'rtl' : 'ltr'), sourceApi: 'alquran.cloud'
                                    }));
                                }
                            }
                        } catch (e) { console.warn("Could not fetch from alquran.cloud API", e); }

                        let firestoreEditions: QuranEdition[] = [];
                        try {
                            const editionsSnapshot = await db.collection('qran_editions').get();
                            if (!editionsSnapshot.empty) firestoreEditions = editionsSnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() }));
                        } catch (e) { console.warn("Could not fetch from Firestore 'qran_editions'", e); }

                        const editionMap = new Map<string, QuranEdition>();
                        [...apiEditions, ...firestoreEditions, ...FULL_DEFAULT_EDITIONS].forEach(e => editionMap.set(e.identifier, e));
                        setAvailableEditions(Array.from(editionMap.values()));
                    })(),
                ]);
            } catch (err) {
                console.error("Error during background initialization:", err);
            } finally {
                setIsBackgroundLoading(false);
            }
        };
        initializeApp();
    }, [fetchCustomEditionData]);

    useEffect(() => {
        availableFonts.forEach(font => {
            if (font.url && !document.querySelector(`link[href="${font.url}"]`)) {
                const link = document.createElement('link');
                link.href = font.url;
                link.rel = 'stylesheet';
                document.head.appendChild(link);
            }
        });
    }, [availableFonts]);

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus, availableFonts, availableEditions,
        fetchCustomEditionData, getEditionUrl,
    };
};

import { useState, useEffect, useCallback, useMemo } from 'react';
import type { QuranEdition, QuranFont, FontSize, BrowsingMode } from '../types';

const QURAN_EDITION_KEY = 'qran_app_edition';
const ACTIVE_EDITIONS_KEY = 'qran_app_active_editions';
const FONT_KEY = 'qran_app_selected_font';
const FONT_SIZE_KEY = 'qran_app_font_size';
const AUDIO_EDITION_KEY = 'qran_app_audio_edition';
const BROWSING_MODE_KEY = 'qran_app_browsing_mode';

const DEFAULT_EDITIONS: QuranEdition[] = [
    { identifier: "quran-simple-clean", language: "ar", name: "المصحف الشريف المبسط (بدون تشكيل)", englishName: "Simple Clean", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "quran-uthmani", language: "ar", name: "المصحف الشريف برسم العثماني", englishName: "Uthmani", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "ar.muyassar", language: "ar", name: "تفسير المیسر", englishName: "Tafsir al-Muyassar", format: "text", type: "tafsir", direction: "rtl", sourceApi: "alquran.cloud" }
];

export const useSettings = (
    availableEditions: QuranEdition[], 
    fetchCustomEditionData: (identifier: string) => void
) => {
    const [selectedFontFamily, setSelectedFontFamily] = useState<string>(() => localStorage.getItem(FONT_KEY) || 'Amiri Quran');
    const [fontSize, setFontSize] = useState<FontSize>(() => (localStorage.getItem(FONT_SIZE_KEY) as FontSize) || 'md');

    const [selectedEdition, setSelectedEdition] = useState<string>(
        () => localStorage.getItem(QURAN_EDITION_KEY) || 'quran-simple-clean'
    );

    const [browsingMode, setBrowsingMode] = useState<BrowsingMode>(() => {
        const storedMode = localStorage.getItem(BROWSING_MODE_KEY) as BrowsingMode;
        if (storedMode) return storedMode;
        return selectedEdition === 'quran-uthmani' ? 'page' : 'full';
    });

    const [activeEditions, setActiveEditions] = useState<QuranEdition[]>(() => {
        try {
            const stored = localStorage.getItem(ACTIVE_EDITIONS_KEY);
            const editions = stored ? JSON.parse(stored) : DEFAULT_EDITIONS;

            const simpleUthmani = availableEditions.find(e => e.identifier === 'quran-uthmani-simple');
            if (simpleUthmani && !editions.some((e: any) => e.identifier === 'quran-uthmani-simple')) {
                editions.push(simpleUthmani);
            }
            return editions;
        } catch (e) {
            console.error("Failed to parse active editions from localStorage", e);
            return DEFAULT_EDITIONS;
        }
    });

    const [selectedAudioEdition, setSelectedAudioEdition] = useState<string>(
        () => localStorage.getItem(AUDIO_EDITION_KEY) || 'ar.alafasy'
    );

    useEffect(() => { localStorage.setItem(QURAN_EDITION_KEY, selectedEdition); }, [selectedEdition]);
    useEffect(() => { localStorage.setItem(ACTIVE_EDITIONS_KEY, JSON.stringify(activeEditions)); }, [activeEditions]);
    useEffect(() => { localStorage.setItem(FONT_KEY, selectedFontFamily); }, [selectedFontFamily]);
    useEffect(() => { localStorage.setItem(FONT_SIZE_KEY, fontSize); }, [fontSize]);
    useEffect(() => { localStorage.setItem(BROWSING_MODE_KEY, browsingMode); }, [browsingMode]);
    useEffect(() => { localStorage.setItem(AUDIO_EDITION_KEY, selectedAudioEdition); }, [selectedAudioEdition]);

    const handleAddEdition = useCallback((identifier: string) => {
        if (activeEditions.some(e => e.identifier === identifier)) {
            alert("هذا المصدر مضاف بالفعل.");
            return;
        }

        const editionToAdd = availableEditions.find(e => e.identifier === identifier);
        let newEdition: QuranEdition;

        if (editionToAdd) {
            newEdition = editionToAdd;
        } else if (identifier.startsWith('http')) {
            let hostname: string;
            try { hostname = new URL(identifier).hostname; } 
            catch (e) {
                alert("الرابط المدخل غير صالح.");
                return;
            }
            newEdition = {
                identifier: identifier, language: 'ar', name: `مصدر مخصص (${hostname})`,
                englishName: 'Custom Source', format: 'text', type: 'quran', direction: 'rtl', sourceApi: 'manual',
            };
        } else {
            alert("لم يتم العثور على المصدر المطلوب.");
            return;
        }

        setActiveEditions(prev => [...prev, newEdition]);
        fetchCustomEditionData(newEdition.identifier);
    }, [activeEditions, availableEditions, fetchCustomEditionData]);

    const handleDeleteEdition = useCallback((identifier: string) => {
        if (identifier === 'quran-simple-clean' || identifier === 'quran-uthmani') {
            alert("لا يمكن حذف المصادر الأساسية.");
            return;
        }
        setActiveEditions(prev => {
            const newEditions = prev.filter(e => e.identifier !== identifier);
            if (selectedEdition === identifier) setSelectedEdition('quran-simple-clean');
            return newEditions;
        });
    }, [selectedEdition]);

    const displayEdition = useMemo(() => {
        const found = activeEditions.find(e => e.identifier === selectedEdition) || availableEditions.find(e => e.identifier === selectedEdition) || DEFAULT_EDITIONS[0];
        if (found.name.includes('القرآن الكريم')) {
            return { ...found, name: found.name.replace(/القرآن الكريم/g, 'المصحف الشريف') };
        }
        return found;
    }, [activeEditions, selectedEdition, availableEditions]);

    return {
        selectedFontFamily, setSelectedFontFamily,
        fontSize, setFontSize,
        browsingMode, setBrowsingMode,
        activeEditions,
        selectedEdition, setSelectedEdition,
        selectedAudioEdition, setSelectedAudioEdition,
        handleAddEdition,
        handleDeleteEdition,
        displayEdition
    };
};

