    <content>< ![CDATA[import React from 'react';

export const normalizeArabicText = (text: string) => {
    return  text
        .replace(/[\u064B-\u0652]/g, '') // Remove harakat
        .replace(/[\u0670\u0671]/g, '') // Remove alef variations
        .replace(/[\u06DC\u06DF\u06E0\u06E1\u06E2\u06E3\u06E4\u06E5\u06E6]/g, '') // Remove diacritics
        .replace(/[\u06D6-\u06D8\u06DE\u06DD]/g, '') // Remove some other marks
        .replace(/[\u0600-\u0605\u061C\u0640\u064B\u064C\u064D\u064E\u064F\u0650\u0651\u0652\u0653\u0654\u0655\u0656\u0657\u0658\u0659\u065A\u065B\u065C\u065D\u065E\u065F]/g, ''); // Remove more diacritics
};

export const formatSurahNameForDisplay = (name:  string, isEnglish: boolean = false) => {
    return isEnglish ?  name : name.replace(/سورة /g, '');
};

export const removeWaqfMarks =  (text: string) => {
    return text.replace(/[\u06D9-\u06DB]/g, '');
};

export const levenshtein = (s1: string, s2: string): number => {
    if (s1.length < s2.length) { return levenshtein(s2, s1); }
    if (s2.length === 0) { return s1.length; }
    let previousRow = Array .from({ length: s2.length + 1 }, (_, i) => i);
    for (let i =  0; i < s1.length; i++) {
        let currentRow = [i + 1];
        for  (let j = 0; j < s2.length; j++) {
            let insertions = previousRow[ j + 1] + 1;
            let deletions = currentRow[j] + 1;
            let substitutions  = previousRow[j] + (s1[i] !== s2[j] ? 1 : 0 );
            currentRow.push(Math.min(insertions, deletions, substitutions));
        }
        previous Row = currentRow;
    }
    return previousRow[s2.length];
};
