export const useAudioPlayer = (
    currentPath: string,
    allQuranData: { [key: string]: SurahData[] } | null,
    selectedAudioEdition: string,
    setSelectedAudioEdition: (id: string) => void,
    fetchCustomEditionData: (id: string) => void
) => {
    const [playbackInfo, setPlaybackInfo] = useState<{
        playlist: Ayah[]; currentIndex: number; isPlaying: boolean;
        trigger?: { ayahsForPlaylist: Ayah[], audioEditionIdentifier: string, startIndex?: number }
    } | null>(null);

    const handleStartPlayback = useCallback((ayahsForPlaylist: Ayah[], audioEditionIdentifier: string, startIndex: number = 0) => {
        const audioEditionDetails = ALL_AUDIO_EDITIONS.find(e => e.identifier === audioEditionIdentifier);
        if (!audioEditionDetails) {
            const fallback = ALL_AUDIO_EDITIONS.find(e => e.identifier === 'ar.alafasy');
            if (fallback) {
                setSelectedAudioEdition('ar.alafasy');
                handleStartPlayback(ayahsForPlaylist, 'ar.alafasy', startIndex);
            } else { alert("لم يتم العثور على المصدر الصوتي المختار."); }
            return;
        }

        const getPlaylistData = () => {
            if (ayahsForPlaylist.length > 0) return ayahsForPlaylist.slice(startIndex);
            const [path] = currentPath.substring(1).split('?');
            const pathParts = path.split('/').filter(Boolean);
            const uthmaniData = allQuranData?.['quran-uthmani'];
            if (pathParts[0] !== 'surah' || !pathParts[1] || !uthmaniData) return [];
            const surahNumber = parseInt(pathParts[1], 10);
            const surahData = uthmaniData.find(s => s.number === surahNumber);
            if (surahData) {
                return surahData.ayahs.map(ayah => ({
                    ...ayah,
                    surah: { number: surahData.number, name: surahData.name, englishName: surahData.englishName, englishNameTranslation: surahData.englishNameTranslation, revelationType: surahData.revelationType, numberOfAyahs: surahData.numberOfAyahs }
                })).slice(startIndex);
            }
            return [];
        };

        const generatePlaylist = (basePlaylist: Ayah[]) => {
            if (basePlaylist.length === 0) { alert("لا يمكن إنشاء قائمة التشغيل."); return null; }
            let finalPlaylist = basePlaylist.map(ayah => {
                let audioUrl = getAudioUrl(ayah, audioEditionDetails);
                if (audioEditionDetails.sourceApi === 'alquran.cloud') {
                    const audioData = allQuranData?.[audioEditionIdentifier];
                    const audioSurah = audioData?.find(s => s.number === ayah.surah?.number);
                    const audioAyah = audioSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
                    audioUrl = audioAyah?.audio;
                }
                return { ...ayah, audio: audioUrl };
            }).filter((item): item is Ayah & { audio: string } => !!item.audio);

            const firstAyahOfPlaylist = basePlaylist[0];
            const surahForPlaylist = firstAyahOfPlaylist.surah;
            const needsBismillah = startIndex === 0 && surahForPlaylist && surahForPlaylist.number !== 1 && surahForPlaylist.number !== 9;
            if (needsBismillah) {
                const bismillahAudioUrl = getBismillahAudioUrl(audioEditionDetails);
                if (bismillahAudioUrl) {
                    finalPlaylist.unshift({ number: 0, numberInSurah: 0, text: 'البسملة', audio: bismillahAudioUrl, surah: surahForPlaylist });
                }
            }
            return finalPlaylist;
        };

        if (audioEditionDetails.sourceApi !== 'alquran.cloud' || allQuranData?.[audioEditionIdentifier]) {
            const playlistBase = getPlaylistData();
            const finalPlaylist = generatePlaylist(playlistBase);
            if (finalPlaylist && finalPlaylist.length > 0) setPlaybackInfo({ playlist: finalPlaylist, currentIndex: 0, isPlaying: true });
            else { alert("لم يتم العثور على بيانات صوتية."); setPlaybackInfo(null); }
        } else {
             fetchCustomEditionData(audioEditionIdentifier);
             setPlaybackInfo({ playlist: [], currentIndex: 0, isPlaying: false, trigger: { ayahsForPlaylist, audioEditionIdentifier, startIndex } });
        }
    }, [allQuranData, fetchCustomEditionData, currentPath, setSelectedAudioEdition]);

    useEffect(() => {
        if (playbackInfo?.trigger && allQuranData?.[playbackInfo.trigger.audioEditionIdentifier]) {
            handleStartPlayback(playbackInfo.trigger.ayahsForPlaylist, playbackInfo.trigger.audioEditionIdentifier, playbackInfo.trigger.startIndex);
        }
    }, [playbackInfo, allQuranData, handleStartPlayback]);

    const handlePlayPause = () => setPlaybackInfo(p => p ? { ...p, isPlaying: !p.isPlaying } : null);
    const handleClosePlayback = () => setPlaybackInfo(null);
    const handleNext = useCallback(() => {
        setPlaybackInfo(p => {
            if (!p) return null;
            const nextIndex = p.currentIndex + 1;
            if (nextIndex >= p.playlist.length) return null;
            return { ...p, currentIndex: nextIndex };
        });
    }, []);
    const handlePrev = () => {
        setPlaybackInfo(p => {
            if (!p) return null;
            const prevIndex = p.currentIndex - 1;
            if (prevIndex < 0) return p;
            return { ...p, currentIndex: prevIndex };
        });
    };

    const currentlyPlayingAyahGlobalNumber = playbackInfo?.playlist[playbackInfo.currentIndex]?.number;
    const selectedAudioEditionDetails = useMemo(() => ALL_AUDIO_EDITIONS.find(e => e.identifier === selectedAudioEdition), [selectedAudioEdition]);

    return {
        playbackInfo,
        currentlyPlayingAyahGlobalNumber,
        selectedAudioEditionDetails,
        handleStartPlayback,
        handlePlayPause,
        handleNext,
        handlePrev,
        handleClosePlayback,
        ALL_AUDIO_EDITIONS
    };
};

import { useState, useEffect, useCallback } from 'react';
import type { Collections, SavedItem } from '../types';
import { db, FieldValue } from '../firebase';
import { generateSyncCode } from '../utils/sync';

const COLLECTIONS_KEY = 'qran_app_collections';
const SYNC_CODE_KEY = 'qran_app_sync_code';

export const useNotebook = () => {
    const [collections, setCollections] = useState<Collections>(() => {
        try {
            const stored = localStorage.getItem(COLLECTIONS_KEY);
            return stored ? JSON.parse(stored) : {};
        } catch (e) {
            console.error("Failed to parse collections from localStorage", e);
            return {};
        }
    });
    const [itemToSave, setItemToSave] = useState<SavedItem | null>(null);

    useEffect(() => {
        localStorage.setItem(COLLECTIONS_KEY, JSON.stringify(collections));
    }, [collections]);

    const handleSaveItem = useCallback((item: SavedItem) => {
        setItemToSave(item);
    }, []);

    const handleConfirmSave = useCallback((collectionId: string, newCollectionName?: string) => {
        if (!itemToSave) return;

        setCollections(prevCollections => {
            const newCollections = { ...prevCollections };
            let targetCollectionId = collectionId;

            if (newCollectionName) {
                targetCollectionId = `coll_${Date.now()}`;
                newCollections[targetCollectionId] = {
                    id: targetCollectionId,
                    name: newCollectionName,
                    items: [],
                    createdAt: Date.now()
                };
            }

            const collection = newCollections[targetCollectionId];
            if (collection && !collection.items.some(i => i.id === itemToSave.id)) {
                collection.items.unshift(itemToSave);
            }

            return newCollections;
        });

        setItemToSave(null);
    }, [itemToSave]);

    const handleDeleteCollection = useCallback((collectionId: string) => {
        if (window.confirm("هل أنت متأكد من حذف هذه المجموعة وكل محتوياتها؟")) {
            setCollections(prev => {
                const newCollections = { ...prev };
                delete newCollections[collectionId];
                return newCollections;
            });
            if(window.location.hash.includes(`/saved/${collectionId}`)) {
                window.location.hash = '#/saved';
            }
        }
    }, []);

    const handleDeleteSavedItem = useCallback((collectionId: string, itemId: string) => {
         setCollections(prev => {
            const newCollections = { ...prev };
            const collection = newCollections[collectionId];
            if (collection) {
                collection.items = collection.items.filter(item => item.id !== itemId);
            }
            return newCollections;
        });
    }, []);

    const updateItemNotes = useCallback((collectionId: string, itemId: string, notes: string) => {
        setCollections(prev => {
            const newCollections = { ...prev };
            const collection = newCollections[collectionId];
            if (collection) {
                const itemIndex = collection.items.findIndex(item => item.id === itemId);
                if (itemIndex > -1) {
                    // Create a new item object to ensure reactivity
                    const updatedItem = { ...collection.items[itemIndex], notes };
                    // Create a new items array
                    const updatedItems = [...collection.items];
                    updatedItems[itemIndex] = updatedItem;
                    // Create a new collection object
                    newCollections[collectionId] = { ...collection, items: updatedItems };
                }
            }
            return newCollections;
        });
    }, []);

    const handleExportNotebook = useCallback(async (): Promise<string> => {
        if (Object.keys(collections).length === 0) {
            throw new Error("دفتر التدبر فارغ. لا يوجد شيء لتصديره.");
        }

        const oldCode = localStorage.getItem(SYNC_CODE_KEY);
        if (oldCode) {
            try {
                await db.collection('temp_notebook_sync').doc(oldCode).delete();
            } catch (error) {
                console.warn(`Could not delete old sync document ${oldCode}:`, error);
            }
        }

        const newCode = generateSyncCode();
        try {
            await db.collection('temp_notebook_sync').doc(newCode).set({
                data: JSON.stringify(collections),
                createdAt: FieldValue.serverTimestamp()
            });
            localStorage.setItem(SYNC_CODE_KEY, newCode);
            return newCode;
        } catch (error: any) {
            console.error("Error exporting notebook: ", error);
            if (error.code === 'permission-denied') throw new Error("فشل التصدير بسبب الصلاحيات.");
            if (error.code === 'unavailable') throw new Error("الخادم غير متاح. يرجى التحقق من اتصالك بالإنترنت.");
            throw new Error("فشل الاتصال بالخادم.");
        }
    }, [collections]);

    const handleImportNotebook = useCallback(async (code: string): Promise<void> => {
        if (!code || code.trim().length !== 6) {
            throw new Error("الرجاء إدخال كود صالح مكون من 6 أحرف وأرقام.");
        }
        const docRef = db.collection('temp_notebook_sync').doc(code.toUpperCase());
        try {
            const doc = await docRef.get();
            if (!doc.exists) {
                throw new Error("الكود غير صالح أو انتهت صلاحيته.");
            }
            const importedData = JSON.parse(doc.data()?.data);

            setCollections(prev => ({ ...prev, ...importedData }));

            await docRef.delete();
        } catch (error: any) {
            console.error("Error importing notebook: ", error);
            if (error instanceof Error && (error.message.includes("الكود غير صالح") || error.message.includes("6 أحرف"))) throw error;
            if (error.code === 'permission-denied') throw new Error("فشل الاستيراد بسبب الصلاحيات.");
            if (error.code === 'unavailable') throw new Error("الخادم غير متاح.");
            throw new Error("فشل استيراد البيانات.");
        }
    }, []);

    return {
        collections,
        itemToSave,
        setItemToSave,
        handleSaveItem,
        handleConfirmSave,
        handleDeleteCollection,
        handleDeleteSavedItem,
        updateItemNotes,
        handleExportNotebook,
        handleImportNotebook
    };
};

