                    </div>
                     <p className="text-sm text-text-muted mt-2">
                        {progress < 100 ? `${30 - Object.values(khatmah.juz_status).filter(s => (s as JuzStatus).status === 'completed').length} جزء متبقي` : "اكتملت الختمة، تقبل الله منكم."}
