export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [dataSourceStatus, setDataSourceStatus] = useState<'primary' | 'fallback'>('primary');
    const [availableFonts, setAvailableFonts] = useState<QuranFont[]>(DEFAULT_FONTS);
    const [availableEditions, setAvailableEditions] = useState<QuranEdition[]>(FULL_DEFAULT_EDITIONS);

    const getEditionUrl = useCallback((edition: QuranEdition): string => {
        const { identifier, sourceApi } = edition;
        if (identifier === 'quran-simple-clean') return 'https://storage.googleapis.com/qurantxt/quran-simple-clean.json';
        if (identifier === 'quran-uthmani') return 'https://storage.googleapis.com/qurantxt/quran-uthmani.json';
        if (identifier === 'quran-uthmani-simple') return 'https://storage.googleapis.com/qurantxt/quran-uthmani.json';
        if (sourceApi === 'manual' || identifier.startsWith('http')) return identifier;
        if (sourceApi === 'fawazahmed0') return `https://cdn.jsdelivr.net/gh/fawazahmed0/quran-api@1/editions/${identifier}.json`;
        return `https://api.alquran.cloud/v1/quran/${identifier}`;
    }, []);

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        if (!editionIdentifier || (allQuranData && allQuranData[editionIdentifier])) return;

        setLoadingEditions(prev => [...prev, editionIdentifier]);
        setError(null);
        const isCoreEdition = editionIdentifier === 'quran-simple-clean' || editionIdentifier === 'quran-uthmani';

        if (editionIdentifier === 'quran-uthmani-simple') {
            try {
                if (!allQuranData?.['quran-uthmani']) {
                    await fetchCustomEditionData('quran-uthmani');
                    return;
                }
                const baseUthmaniData = allQuranData['quran-uthmani'];
                const processedSurahs: SurahData[] = baseUthmaniData.map((surah: any) => ({
                    ...surah,
                    ayahs: surah.ayahs.map((ayah: any) => ({ ...ayah, text: removeWaqfMarks(ayah.text) }))
                }));
                setAllQuranData(prev => ({ ...prev, [editionIdentifier]: processedSurahs }));
            } catch (err) {
                console.error("Failed to generate Uthmani Simple edition", err);
                setError("فشل في توليد النسخة العثمانية المبسطة.");
            } finally {
                setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
            }
            return;
        }

        const editionToFetch = availableEditions.find(e => e.identifier === editionIdentifier) || { identifier: editionIdentifier, sourceApi: 'manual' } as QuranEdition;
        if (!editionToFetch) {
            console.warn(`Edition ${editionIdentifier} not found in availableEditions.`);
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
            return;
        }

        const url = getEditionUrl(editionToFetch);
        const processApiData = (apiData: any, urlForTypeCheck: string): SurahData[] => {
            if (urlForTypeCheck.includes('fawazahmed0')) {
                return (apiData.quran || []).map((surah: any) => ({ ...surah, ayahs: (surah.verses || []).map((verse: any) => ({ ...verse, numberInSurah: verse.id, number: -1 })) }));
            }
            if (apiData.code === 200 && apiData.data && apiData.data.surahs) return apiData.data.surahs;
            if (apiData.code === 200 && apiData.data && apiData.data.ayahs) {
                const surahsMap: { [key: number]: SurahData } = {};
                for (const ayah of apiData.data.ayahs) {
                    if (!surahsMap[ayah.surah.number]) surahsMap[ayah.surah.number] = { ...ayah.surah, ayahs: [] };
                    surahsMap[ayah.surah.number].ayahs.push(ayah);
                }
                return Object.values(surahsMap).sort((a, b) => a.number - b.number);
            }
            throw new Error('Invalid or unexpected API data structure');
        };

        try {
            const response = await fetch(url);
            if (!response.ok) throw new Error(`Network response was not ok: ${response.statusText}`);
            const apiData = await response.json();
            const surahs = processApiData(apiData, url);
            setAllQuranData(prev => ({ ...prev, [editionIdentifier]: surahs }));
        } catch (err) {
            console.error(`Failed to fetch edition ${editionIdentifier}:`, err);
            if (isCoreEdition) setError(`فشل تحميل بيانات المصحف الأساسية. قد تكون هناك مشكلة في الاتصال بالإنترنت.`);
        } finally {
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
        }
    }, [allQuranData, availableEditions, getEditionUrl]);

    // Create a stable ref for the fetch function to break the useEffect dependency cycle.
    const fetchCustomEditionDataRef = useRef(fetchCustomEditionData);
    useEffect(() => {
        fetchCustomEditionDataRef.current = fetchCustomEditionData;
    }, [fetchCustomEditionData]);

    useEffect(() => {
        const initializeApp = async () => {
            setIsInitialLoading(true);
            await fetchCustomEditionDataRef.current('quran-simple-clean');
            setIsInitialLoading(false);

            setIsBackgroundLoading(true);
            try {
                await Promise.all([
                    fetchCustomEditionDataRef.current('quran-uthmani'),
                    (async () => {
                        const fontsSnapshot = await db.collection('qran_fonts').get();
                        if (!fontsSnapshot.empty) setAvailableFonts(fontsSnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() })));
                    })(),
                    (async () => {
                        let apiEditions: QuranEdition[] = [];
                        try {
                            const response = await fetch('https://api.alquran.cloud/v1/edition');
                            if (response.ok) {
                                const data = await response.json();
                                if (data.code === 200 && Array.isArray(data.data)) {
                                    apiEditions = data.data.map((e: any) => ({
                                        identifier: e.identifier, language: e.language, name: e.name, englishName: e.englishName,
                                        format: e.format, type: e.type, direction: e.direction || (e.language === 'ar' ? 'rtl' : 'ltr'), sourceApi: 'alquran.cloud'
                                    }));
                                }
                            }
                        } catch (e) { console.warn("Could not fetch from alquran.cloud API", e); }

                        let firestoreEditions: QuranEdition[] = [];
                        try {
                            const editionsSnapshot = await db.collection('qran_editions').get();
                            if (!editionsSnapshot.empty) firestoreEditions = editionsSnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() }));
                        } catch (e) { console.warn("Could not fetch from Firestore 'qran_editions'", e); }

                        const editionMap = new Map<string, QuranEdition>();
                        [...apiEditions, ...firestoreEditions, ...FULL_DEFAULT_EDITIONS].forEach(e => editionMap.set(e.identifier, e));
                        setAvailableEditions(Array.from(editionMap.values()));
                    })(),
                ]);
            } catch (err) {
                console.error("Error during background initialization:", err);
            } finally {
                setIsBackgroundLoading(false);
            }
        };
        initializeApp();
    }, []); // Empty dependency array ensures this effect runs only once on mount.

    useEffect(() => {
        availableFonts.forEach(font => {
            if (font.url && !document.querySelector(`link[href="${font.url}"]`)) {
                const link = document.createElement('link');
                link.href = font.url;
                link.rel = 'stylesheet';
                document.head.appendChild(link);
            }
        });
    }, [availableFonts]);

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus, availableFonts, availableEditions,
        fetchCustomEditionData, getEditionUrl,
    };
};

// service-worker.js

const STATIC_CACHE_NAME = 'qran-top-static-v11'; // Version bump to force update
const DATA_CACHE_NAME = 'qran-top-data-v9'; // Version bump to force update

// Core data files that are essential for the app to work offline.
const CORE_DATA_URLS = [
  'https://storage.googleapis.com/qurantxt/quran-simple-clean.json',
  'https://storage.googleapis.com/qurantxt/quran-uthmani.json',
];

// The "app shell" - minimal files needed for the UI to render.
const STATIC_FILES_TO_CACHE = [
  './',
  './index.html',
  './index.tsx',
  './index.css',
  './Uthman.ttf',
  './manifest.json',
  './thumbnail.png',
  // Note: aistudio-host.js is not included as it's injected and managed by the environment.
];

// Install event: cache static assets and core data.
self.addEventListener('install', event => {
  console.log('[Service Worker] Install');
  event.waitUntil(
    Promise.all([
      caches.open(STATIC_CACHE_NAME).then(cache => {
        console.log('[Service Worker] Pre-caching static app shell');
        // Use ignoreSearch to cache the base file without query parameters if needed, though addAll is direct.
        const requests = STATIC_FILES_TO_CACHE.map(url => new Request(url, { cache: 'reload' }));
        return cache.addAll(requests);
      }),
      caches.open(DATA_CACHE_NAME).then(cache => {
        console.log('[Service Worker] Pre-caching core Quran data');
        const requests = CORE_DATA_URLS.map(url => new Request(url, { cache: 'reload' }));
        return cache.addAll(requests);
      })
    ]).then(() => {
        console.log('[Service Worker] Installation complete. Activating immediately.');
        return self.skipWaiting();
    })
  );
});

// Activate event: clean up old caches.
self.addEventListener('activate', event => {
  console.log('[Service Worker] Activate');
  const cacheWhitelist = [STATIC_CACHE_NAME, DATA_CACHE_NAME];
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            console.log('[Service Worker] Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    }).then(() => {
        console.log('[Service Worker] Activation complete. Claiming clients.');
        return self.clients.claim();
    })
  );
});

// Fetch event: handle network requests with different strategies.
self.addEventListener('fetch', event => {
  const { request } = event;

  // Defensive check: The URL constructor can fail on non-standard schemes
  // like 'chrome-extension://' or 'about:blank'. We only want to handle http/https requests.
  if (!request.url.startsWith('http')) {
    return;
  }

  const url = new URL(request.url);

  // Ignore requests that are not GET.
  if (request.method !== 'GET') {
    return;
  }

  // Ignore requests to Firebase, as it has its own offline persistence mechanism.
  if (url.hostname.includes('firebase') || url.hostname.includes('googleapis.com')) {
    // Exception: Allow our GCS bucket for Quran data
    if (url.hostname !== 'storage.googleapis.com' || !url.pathname.startsWith('/qurantxt/')) {
        return;
    }
  }

  // Strategy 1: Stale-While-Revalidate for API calls (data).
  // This serves the cached version immediately for speed, then updates the cache in the background.
  if (url.hostname === 'storage.googleapis.com' || url.hostname === 'api.alquran.cloud' || url.hostname === 'cdn.jsdelivr.net' || url.hostname === 'everyayah.com' || url.hostname === 'cdn.islamic.network') {
    event.respondWith(
      caches.open(DATA_CACHE_NAME).then(cache => {
        return cache.match(request).then(cachedResponse => {
          const fetchPromise = fetch(request).then(networkResponse => {
            // Check if we received a valid response before caching
            if (networkResponse && networkResponse.status === 200) {
              cache.put(request, networkResponse.clone());
            }
            return networkResponse;
          }).catch(err => {
            // Network fetch failed, which is expected offline.
            // The cachedResponse will be used if it exists.
            console.warn('[Service Worker] Network fetch failed for:', request.url);
          });

          return cachedResponse || fetchPromise;
        });
      })
    );
    return; // End execution for this strategy
  }

  // Strategy 2: Cache First for static assets (app shell).
  // This is ideal for files that don't change often.
  // We use ignoreSearch: true to ensure cache-busting parameters don't prevent cache hits.
  event.respondWith(
    caches.match(request, { ignoreSearch: true }).then(cachedResponse => {
      if (cachedResponse) {
        return cachedResponse;
      }
      // If not in cache, fetch from network.
      return fetch(request).then(networkResponse => {
        // Optional: Cache newly fetched static assets if needed, but primary caching is on install.
        return networkResponse;
      });
    })
  );
});

// Listen for a message from the client to activate the new service worker.
self.addEventListener('message', event => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

