import React, { useEffect, useRef, useState, useMemo } from 'react';
import type { SurahData, QuranEdition, QuranFont, SavedAyahItem, Ayah, FontSize, BrowsingMode } from '../types';
import { PlayIcon, SpinnerIcon, ArrowLeftIcon, ArrowRightIcon } from './icons';
import AudioEditionSelector from './AudioEditionSelector';
import AyahActionPopover from './AyahActionPopover';
import AyahRenderer from './AyahRenderer';
import { formatSurahNameForDisplay } from '../utils/text';

interface SurahDetailViewProps {
  surah: SurahData;
  highlightAyahNumber: number | null;
  onWordClick: (query: string, editionIdentifier: string, position: { surah: number; ayah: number; wordIndex: number; }) => void;
  displayEdition: QuranEdition;
  selectedFont: string;
  fontSize: FontSize;
  browsingMode: BrowsingMode;
  onSaveAyah: (item: SavedAyahItem) => void;
  onSearchByAyahNumber: (ayahNumber: number) => void;
  // --- Props for audio playback ---
  currentlyPlayingAyahGlobalNumber: number | null;
  isPlaybackLoading: boolean;
  onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
  allAudioEditions: QuranEdition[];
  selectedAudioEdition: string;
  onAudioEditionChange: (identifier: string) => void;
  // --- Prop for word popover ---
  simpleCleanData: SurahData[];
  hizbQuarterStartMap: Map<number, number>;
}

const SurahDetailView: React.FC<SurahDetailViewProps> = ({ 
  surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode,
  onSaveAyah, onSearchByAyahNumber,
  currentlyPlayingAyahGlobalNumber, isPlaybackLoading, onStartPlayback,
  allAudioEditions, selectedAudioEdition, onAudioEditionChange,
  simpleCleanData, hizbQuarterStartMap
}) => {
  const highlightRef = useRef<HTMLSpanElement>(null);
  const playingAyahRef = useRef<HTMLSpanElement>(null);
  const wordPopoverRef = useRef<HTMLDivElement>(null);

  const [activePopover, setActivePopover] = useState<{ ayah: Ayah; triggerElement: HTMLElement } | null>(null);
  const [copiedAyah, setCopiedAyah] = useState<number | null>(null);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const [wordPopoverState, setWordPopoverState] = useState<{
    ayahNumberInSurah: number;
    simpleText: string;
    triggerElement: HTMLElement;
  } | null>(null);

  const [touchStartX, setTouchStartX] = useState<number | null>(null);
  const [touchCurrentX, setTouchCurrentX] = useState<number | null>(null);

  const prevSurahNumber = useRef<number | null>(null);

  const { ayahsByPage, firstPage, lastPage, getPageForAyahNumber } = useMemo(() => {
    const map = new Map<number, Ayah[]>();
    const ayahNumToPageMap = new Map<number, number>();
    if (!surah || !surah.ayahs || surah.ayahs.length === 0) {
        return { ayahsByPage: map, firstPage: 1, lastPage: 1, getPageForAyahNumber: (n: number) => undefined };
    }
    let minPage = Infinity;
    let maxPage = -Infinity;
    for (const ayah of surah.ayahs) {
        if (ayah.page) {
            if (!map.has(ayah.page)) {
                map.set(ayah.page, []);
            }
            map.get(ayah.page)!.push(ayah);
            minPage = Math.min(minPage, ayah.page);
            maxPage = Math.max(maxPage, ayah.page);
            ayahNumToPageMap.set(ayah.numberInSurah, ayah.page);
        }
    }
    const getPageForAyahNumber = (num: number) => ayahNumToPageMap.get(num);
    return { ayahsByPage: map, firstPage: minPage === Infinity ? 1 : minPage, lastPage: maxPage === -Infinity ? 1 : maxPage, getPageForAyahNumber };
  }, [surah]);

  useEffect(() => {
    let targetPage: number | undefined;

    if (highlightAyahNumber) {
        targetPage = getPageForAyahNumber(highlightAyahNumber);
    } else if (currentlyPlayingAyahGlobalNumber) {
        const playingAyah = surah.ayahs.find(a => a.number === currentlyPlayingAyahGlobalNumber);
        if (playingAyah) {
            targetPage = getPageForAyahNumber(playingAyah.numberInSurah);
        }
    }

    setCurrentPage(targetPage || firstPage);
  }, [surah.number, highlightAyahNumber, currentlyPlayingAyahGlobalNumber, getPageForAyahNumber, firstPage]);


  useEffect(() => {
    const currentSurahNumber = surah.number;
    const isNewSurahView = prevSurahNumber.current !== currentSurahNumber;

    if (isNewSurahView) {
        prevSurahNumber.current = currentSurahNumber;
    }

    let elementToScroll: HTMLElement | null = null;
    let shouldPulse = false;

    if (currentlyPlayingAyahGlobalNumber !== null && surah.ayahs.some(a => a.number === currentlyPlayingAyahGlobalNumber)) {
        elementToScroll = playingAyahRef.current;
        shouldPulse = false;
    }
    else if (isNewSurahView && highlightAyahNumber) {
        elementToScroll = highlightRef.current;
        shouldPulse = true;
    }

    if (elementToScroll) {
        const scrollTimer = setTimeout(() => {
            elementToScroll?.scrollIntoView({
                behavior: 'smooth',
                block: 'center',
            });

            if (shouldPulse) {
                elementToScroll?.classList.add('animate-highlight-pulse');
                setTimeout(() => {
                    elementToScroll?.classList.remove('animate-highlight-pulse');
                }, 3000);
            }
        }, 150); // Delay to allow page transition to finish

        return () => clearTimeout(scrollTimer);
    } else if (isNewSurahView && browsingMode === 'full') {
        window.scrollTo(0, 0);
    }
  }, [highlightAyahNumber, currentlyPlayingAyahGlobalNumber, surah.number, browsingMode, currentPage]);


  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        const target = event.target as Node;
        if (!(target as HTMLElement).closest('.popover-trigger, .popover-content')) {
            setActivePopover(null);
        }
        if (wordPopoverRef.current && !wordPopoverRef.current.contains(target)) {
            if (!(event.target as HTMLElement).closest('.word-trigger')) {
                setWordPopoverState(null);
            }
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const handlePlaySurah = () => {
    onStartPlayback([], selectedAudioEdition);
  };

  if (displayEdition.format === 'audio') {
    return (
      <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
        <main className="bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300">
          <h3 className="text-xl font-bold mb-4 text-center text-primary-text">{displayEdition.name}</h3>
          <div className="flex flex-col gap-2">
            {surah.ayahs.map(ayah => (
              ayah.audio ? (
                <div key={ayah.number} className="flex items-center gap-4 py-2 px-3 my-1 bg-surface-subtle rounded-lg">
                  <span className="font-bold text-primary-text">الآية {ayah.numberInSurah}</span>
                  <audio
                    controls
                    src={ayah.audio}
                    className="w-full h-10"
                    preload="metadata"
                    title={`الاستماع للآية ${ayah.numberInSurah}`}
                  >
                    متصفحك لا يدعم عنصر الصوت.
                  </audio>
                </div>
              ) : null
            ))}
          </div>
        </main>
      </div>
    );
  }

  const getQuranTextStyle = () => {
    const fallbackFonts = "'Uthman', 'Amiri Quran', 'Tajawal', sans-serif";
    const isImlaei = displayEdition.identifier.includes('simple-clean');

    if (displayEdition.type === 'quran' && displayEdition.direction === 'rtl') {
      return {
        className: `${isImlaei ? 'imlai-font' : 'uthmani-font'} quran-text-${fontSize}`,
        style: {
          fontFamily: `"${selectedFont}", ${fallbackFonts}`,
        }
      };
    }

    return { className: 'font-quran text-2xl', style: {} };
  }

  const { className: quranTextClass, style: quranTextStyle } = getQuranTextStyle();

  const handleSaveClick = (ayah: Ayah) => {
    onSaveAyah({
      type: 'ayah',
      id: `${ayah.surah?.number || surah.number}:${ayah.numberInSurah}`,
      surah: ayah.surah?.number || surah.number,
      ayah: ayah.numberInSurah,
      text: ayah.text || '',
      createdAt: Date.now(),
    });
    setActivePopover(null);
  };

  const handleCopyAyah = (ayah: Ayah) => {
    const surahName = ayah.surah?.name || surah.name;
    const cleanSurahName = formatSurahNameForDisplay(surahName);
    const textToCopy = `"${ayah.text || ''}" (سورة ${cleanSurahName} - الآية ${ayah.numberInSurah})`;
    navigator.clipboard.writeText(textToCopy).then(() => {
        setCopiedAyah(ayah.number);
        setTimeout(() => setCopiedAyah(null), 2000);
        setActivePopover(null);
    });
  };

  const handleSearchByAyahText = (ayah: Ayah) => {
    const simpleSurah = simpleCleanData.find(s => s.number === (ayah.surah?.number || surah.number));
    const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
    const simpleTextToSearch = simpleAyah?.text;

    if (simpleTextToSearch) {
        onWordClick(simpleTextToSearch, 'quran-simple-clean', { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    } else if (ayah.text) {
        onWordClick(ayah.text, displayEdition.identifier, { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    }
    setActivePopover(null);
  };

  const handlePlayFromAyah = (ayah: Ayah) => {
    const startIndex = surah.ayahs.findIndex(a => a.numberInSurah === ayah.numberInSurah);
    if (startIndex !== -1) {
        onStartPlayback([], selectedAudioEdition, startIndex);
    }
    setActivePopover(null);
  };

  const handleNextPage = () => {
    setCurrentPage(p => {
        const nextPage = p < lastPage ? p + 1 : p;
        if (nextPage !== p) window.scrollTo({ top: 0, behavior: 'smooth' });
        return nextPage;
    });
  };

  const handlePrevPage = () => {
      setCurrentPage(p => {
          const prevPage = p > firstPage ? p - 1 : p;
          if (prevPage !== p) window.scrollTo({ top: 0, behavior: 'smooth' });
          return prevPage;
      });
  };

  const SWIPE_THRESHOLD = 50;

  const handleTouchStart = (e: React.TouchEvent) => {
      if (browsingMode !== 'page') return;
      setTouchStartX(e.targetTouches[0].clientX);
      setTouchCurrentX(e.targetTouches[0].clientX);
  };

  const handleTouchMove = (e: React.TouchEvent) => {
      if (touchStartX === null || browsingMode !== 'page') return;
      setTouchCurrentX(e.targetTouches[0].clientX);
  };

  const handleTouchEnd = () => {
      if (touchStartX === null || touchCurrentX === null || browsingMode !== 'page') return;

      const deltaX = touchStartX - touchCurrentX;

      if (Math.abs(deltaX) > SWIPE_THRESHOLD) {
          if (deltaX > 0) { 
              if (currentPage < lastPage) {
                  handleNextPage();
              }
          } else { 
              if (currentPage > firstPage) {
                  handlePrevPage();
              }
          }
      }

      setTouchStartX(null);
      setTouchCurrentX(null);
  };

  const swipeTranslateX = useMemo(() => {
      if (touchStartX === null || touchCurrentX === null || browsingMode !== 'page') {
          return 0;
      }
      const deltaX = touchCurrentX - touchStartX;

      if ((deltaX < 0 && currentPage >= lastPage) || (deltaX > 0 && currentPage <= firstPage)) {
          return deltaX / 3;
      }
      return deltaX;
  }, [touchStartX, touchCurrentX, browsingMode, currentPage, firstPage, lastPage]);

  const ayahsToRender = useMemo(() => browsingMode === 'page'
      ? (ayahsByPage.get(currentPage) || [])
      : surah.ayahs, [browsingMode, ayahsByPage, currentPage, surah.ayahs]);

  const pageInfo = useMemo(() => {
    if (browsingMode !== 'page' || !hizbQuarterStartMap || ayahsToRender.length === 0) return null;

    const firstAyah = ayahsToRender[0];
    let surahName = firstAyah.surah?.name || surah.name;
    surahName = surahName.replace(/^سُورَةُ\s*/, '').trim();

    const juzNumber = firstAyah.juz;
    const hizbNumber = firstAyah.hizbQuarter ? Math.floor((firstAyah.hizbQuarter - 1) / 4) + 1 : null;

    const markers: {label: string}[] = [];
    const processedQuarters = new Set<number>();

    if (hizbNumber) {
        const startOfHizbQuarter = (hizbNumber - 1) * 4 + 1;
        if(hizbQuarterStartMap.get(startOfHizbQuarter) === firstAyah.number) {
            markers.push({ label: `الحزب ${hizbNumber}`});
        }
    }

    for(const ayah of ayahsToRender) {
        if(ayah.hizbQuarter && hizbQuarterStartMap.get(ayah.hizbQuarter) === ayah.number) {
            if (processedQuarters.has(ayah.hizbQuarter)) continue;

            const quarterType = (ayah.hizbQuarter - 1) % 4;
            if (quarterType === 1) markers.push({ label: 'ربع الحزب'});
            else if (quarterType === 2) markers.push({ label: 'نصف الحزب'});
            else if (quarterType === 3) markers.push({ label: 'ثلاثة أرباع الحزب'});

            processedQuarters.add(ayah.hizbQuarter);
        }
    }

    return {
        surahName,
        juzNumber,
        markers,
        side: currentPage % 2 === 0 ? 'left' : 'right'
    };
  }, [currentPage, browsingMode, ayahsToRender, hizbQuarterStartMap, surah.name]);

  const isBismillahApplicable = surah.number !== 1 && surah.number !== 9 && displayEdition.type === 'quran' && displayEdition.direction === 'rtl';

  // FIX: Add a defensive check to prevent duplicate Bismillah.
  const firstAyahTextOnPage = ayahsToRender[0]?.text || '';
  const firstAyahOnPageHasBismillah = /^بِسْمِ ٱللَّهِ/.test(firstAyahTextOnPage);

  const shouldShowBismillah = isBismillahApplicable && !firstAyahOnPageHasBismillah && (browsingMode === 'full' || (browsingMode === 'page' && currentPage === firstPage));

  return (
    <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
      {displayEdition.type === 'quran' && displayEdition.direction === 'rtl' && (
        <div className="w-full max-w-4xl mx-auto mb-4 flex items-stretch justify-center gap-3">
            <div className="flex-grow">
                <AudioEditionSelector
                    audioEditions={allAudioEditions}
                    selectedAudioEdition={selectedAudioEdition}
                    onSelect={onAudioEditionChange}
                />
            </div>
            <button
                onClick={handlePlaySurah}
                disabled={isPlaybackLoading || allAudioEditions.length === 0}
                className="flex items-center gap-3 px-6 py-3 bg-surface border-2 border-primary text-primary-text rounded-lg shadow-sm hover:shadow-md hover:bg-surface-hover transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary disabled:opacity-60 disabled:cursor-not-allowed flex-shrink-0"
                aria-label="استماع للسورة"
            >
                {isPlaybackLoading ? <SpinnerIcon className="w-6 h-6"/> : <PlayIcon className="w-6 h-6"/>}
                <span className="text-lg font-semibold hidden sm:inline">{isPlaybackLoading ? 'جاري التحضير...' : 'استماع'}</span>
            </button>
        </div>
      )}
      <div className="overflow-hidden rounded-lg">
        {browsingMode === 'page' && !displayEdition.identifier.includes('simple-clean') ? (
             <div
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    transform: `translateX(${swipeTranslateX}px)`,
                    transition: touchStartX === null ? 'transform 0.3s ease-out' : 'none',
                }}
             >
                <div className="mushaf-page" style={{ touchAction: 'pan-y' }}>
                    {pageInfo?.markers.map((marker, index) => (
                         <div key={index} className={`hizb-marker ${pageInfo.side}`}>{marker.label}</div>
                    ))}
                    <header className="mushaf-header">
                        <span>{pageInfo?.juzNumber && `الجزء ${pageInfo.juzNumber}`}</span>
                        <span>{pageInfo?.surahName && `سورة ${pageInfo.surahName}`}</span>
                    </header>

                    {shouldShowBismillah && (
                        <div className="text-center mb-8 font-bismillah text-2xl text-primary-text-strong">
                            بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ
                        </div>
                    )}
                    <main dir={displayEdition.direction} style={quranTextStyle} className={`text-text-primary ${quranTextClass} text-justify`}>
                        <AyahRenderer {...{ ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode, currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState, setActivePopover, playingAyahRef, highlightRef }} />
                    </main>

                    <footer className="mushaf-footer">
                        <span>{currentPage}</span>
                    </footer>
                </div>
            </div>
        ) : (
            <main
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    transform: `translateX(${swipeTranslateX}px)`,
                    transition: touchStartX === null ? 'transform 0.3s ease-out' : 'none',
                    touchAction: browsingMode === 'page' ? 'pan-y' : 'auto',
                }}
                className={`bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300 ${browsingMode === 'page' ? 'cursor-grab active:cursor-grabbing' : ''}`}
            >
                {browsingMode === 'page' && lastPage > firstPage && (
                    <div className="text-center mb-6 -mt-2">
                        <span className="font-mono text-sm font-semibold text-text-muted select-none">
                            {currentPage}
                        </span>
                    </div>
                )}
                {shouldShowBismillah && (
                    <div className="text-center mb-8 font-bismillah text-2xl text-primary-text-strong">
                        بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ
                    </div>
                )}
                <div dir={displayEdition.direction} style={quranTextStyle} className={`text-text-primary ${quranTextClass} ${displayEdition.direction === 'ltr' ? 'text-left' : 'text-right'}`}>
                     <AyahRenderer {...{ ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode, currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState, setActivePopover, playingAyahRef, highlightRef }} />
                </div>
            </main>
        )}
      </div>

      {browsingMode === 'page' && lastPage > firstPage && (
          <div className="mt-6 flex items-center justify-between p-2 bg-surface rounded-full shadow-md border border-border-default">
              <button 
                  onClick={handlePrevPage} 
                  disabled={currentPage <= firstPage}
                  className="flex items-center gap-2 px-4 py-2 rounded-full text-text-secondary hover:bg-surface-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                  <ArrowRightIcon className="w-5 h-5" />
                  <span className="font-semibold hidden sm:inline">الصفحة السابقة</span>
              </button>
              <div className="font-bold text-lg text-text-primary font-mono select-none">
                  {currentPage}
              </div>
              <button 
                  onClick={handleNextPage} 
                  disabled={currentPage >= lastPage}
                  className="flex items-center gap-2 px-4 py-2 rounded-full text-text-secondary hover:bg-surface-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                  <span className="font-semibold hidden sm:inline">الصفحة التالية</span>
                  <ArrowLeftIcon className="w-5 h-5" />
              </button>
          </div>
      )}

      {wordPopoverState && (
         <div 
            ref={wordPopoverRef}
            className="absolute p-3 bg-surface rounded-lg shadow-lg border border-border-default flex items-center gap-2 z-20 animate-fade-in flex-wrap leading-loose"
            style={(() => {
                if (!wordPopoverState.triggerElement) return { opacity: 0, top: 0, left: 0 };
                const rect = wordPopoverState.triggerElement.getBoundingClientRect();
                return {
                    top: `${rect.bottom + window.scrollY + 5}px`,
                    left: `${rect.left + window.scrollX + rect.width / 2}px`,
                    transform: 'translateX(-50%)',
                };
            })()}
        >
            {wordPopoverState.simpleText.split(' ').map((word, index) => (
                <button
                    key={index}
                    onClick={() => {
                        onWordClick(word, 'quran-simple-clean', { surah: surah.number, ayah: wordPopoverState.ayahNumberInSurah, wordIndex: index });
                        setWordPopoverState(null);
                    }}
                    className="px-2 py-1 bg-surface-subtle rounded-md hover:bg-primary/20 transition-colors"
                >
                    {word}
                </button>
            ))}
        </div>
      )}

      {activePopover && (
        <AyahActionPopover 
            activePopover={activePopover}
            onClose={() => setActivePopover(null)}
            onSave={handleSaveClick}
            onCopy={handleCopyAyah}
            onSearchText={handleSearchByAyahText}
            onSearchNumber={onSearchByAyahNumber}
            onPlayFrom={handlePlayFromAyah}
            copiedAyah={copiedAyah}
        />
      )}

    </div>
  );
};

export default SurahDetailView;

// service-worker.js

const STATIC_CACHE_NAME = 'qran-top-static-v12'; // Version bump to force update
const DATA_CACHE_NAME = 'qran-top-data-v10'; // Version bump to force update

// Core data files that are essential for the app to work offline.
const CORE_DATA_URLS = [
  'https://storage.googleapis.com/qurantxt/quran-simple-clean.json',
  'https://storage.googleapis.com/qurantxt/quran-uthmani.json',
];

// The "app shell" - minimal files needed for the UI to render.
const STATIC_FILES_TO_CACHE = [
  './',
  './index.html',
  './index.tsx',
  './index.css',
  './Uthman.ttf',
  './manifest.json',
  './thumbnail.png',
  // Note: aistudio-host.js is not included as it's injected and managed by the environment.
];

// Install event: cache static assets and core data.
self.addEventListener('install', event => {
  console.log('[Service Worker] Install');
  event.waitUntil(
    Promise.all([
      caches.open(STATIC_CACHE_NAME).then(cache => {
        console.log('[Service Worker] Pre-caching static app shell');
        // Use ignoreSearch to cache the base file without query parameters if needed, though addAll is direct.
        const requests = STATIC_FILES_TO_CACHE.map(url => new Request(url, { cache: 'reload' }));
        return cache.addAll(requests);
      }),
      caches.open(DATA_CACHE_NAME).then(cache => {
        console.log('[Service Worker] Pre-caching core Quran data');
        const requests = CORE_DATA_URLS.map(url => new Request(url, { cache: 'reload' }));
        return cache.addAll(requests);
      })
    ]).then(() => {
        console.log('[Service Worker] Installation complete. Activating immediately.');
        return self.skipWaiting();
    })
  );
});

// Activate event: clean up old caches.
self.addEventListener('activate', event => {
  console.log('[Service Worker] Activate');
  const cacheWhitelist = [STATIC_CACHE_NAME, DATA_CACHE_NAME];
  event.waitUntil(
    caches.keys().then(cacheNames => {
      return Promise.all(
        cacheNames.map(cacheName => {
          if (cacheWhitelist.indexOf(cacheName) === -1) {
            console.log('[Service Worker] Deleting old cache:', cacheName);
            return caches.delete(cacheName);
          }
        })
      );
    }).then(() => {
        console.log('[Service Worker] Activation complete. Claiming clients.');
        return self.clients.claim();
    })
  );
});

// Fetch event: handle network requests with different strategies.
self.addEventListener('fetch', event => {
  const { request } = event;

  // Defensive check: The URL constructor can fail on non-standard schemes
  // like 'chrome-extension://' or 'about:blank'. We only want to handle http/https requests.
  if (!request.url.startsWith('http')) {
    return;
  }

  const url = new URL(request.url);

  // Ignore requests that are not GET.
  if (request.method !== 'GET') {
    return;
  }

  // Ignore requests to Firebase, as it has its own offline persistence mechanism.
  if (url.hostname.includes('firebase') || url.hostname.includes('googleapis.com')) {
    // Exception: Allow our GCS bucket for Quran data
    if (url.hostname !== 'storage.googleapis.com' || !url.pathname.startsWith('/qurantxt/')) {
        return;
    }
  }

  // Strategy 1: Stale-While-Revalidate for API calls (data).
  // This serves the cached version immediately for speed, then updates the cache in the background.
  if (url.hostname === 'storage.googleapis.com' || url.hostname === 'api.alquran.cloud' || url.hostname === 'cdn.jsdelivr.net' || url.hostname === 'everyayah.com' || url.hostname === 'cdn.islamic.network') {
    event.respondWith(
      caches.open(DATA_CACHE_NAME).then(cache => {
        return cache.match(request).then(cachedResponse => {
          const fetchPromise = fetch(request).then(networkResponse => {
            // Check if we received a valid response before caching
            if (networkResponse && networkResponse.status === 200) {
              cache.put(request, networkResponse.clone());
            }
            return networkResponse;
          }).catch(err => {
            // Network fetch failed, which is expected offline.
            // The cachedResponse will be used if it exists.
            console.warn('[Service Worker] Network fetch failed for:', request.url);
          });

          return cachedResponse || fetchPromise;
        });
      })
    );
    return; // End execution for this strategy
  }

  // Strategy 2: Cache First for static assets (app shell).
  // This is ideal for files that don't change often.
  // We use ignoreSearch: true to ensure cache-busting parameters don't prevent cache hits.
  event.respondWith(
    caches.match(request, { ignoreSearch: true }).then(cachedResponse => {
      if (cachedResponse) {
        return cachedResponse;
      }
      // If not in cache, fetch from network.
      return fetch(request).then(networkResponse => {
        // Optional: Cache newly fetched static assets if needed, but primary caching is on install.
        return networkResponse;
      });
    })
  );
});

// Listen for a message from the client to activate the new service worker.
self.addEventListener('message', event => {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

import React, { useEffect, useRef, useState, useMemo } from 'react';
import type { SurahData, QuranEdition, QuranFont, SavedAyahItem, Ayah, FontSize, BrowsingMode } from '../types';
import { PlayIcon, SpinnerIcon, ArrowLeftIcon, ArrowRightIcon } from './icons';
import AudioEditionSelector from './AudioEditionSelector';
import AyahActionPopover from './AyahActionPopover';
import AyahRenderer from './AyahRenderer';
import { formatSurahNameForDisplay } from '../utils/text';

interface SurahDetailViewProps {
  surah: SurahData;
  highlightAyahNumber: number | null;
  onWordClick: (query: string, editionIdentifier: string, position: { surah: number; ayah: number; wordIndex: number; }) => void;
  displayEdition: QuranEdition;
  selectedFont: string;
  fontSize: FontSize;
  browsingMode: BrowsingMode;
  onSaveAyah: (item: SavedAyahItem) => void;
  onSearchByAyahNumber: (ayahNumber: number) => void;
  // --- Props for audio playback ---
  currentlyPlayingAyahGlobalNumber: number | null;
  isPlaybackLoading: boolean;
  onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
  allAudioEditions: QuranEdition[];
  selectedAudioEdition: string;
  onAudioEditionChange: (identifier: string) => void;
  // --- Prop for word popover ---
  simpleCleanData: SurahData[];
  hizbQuarterStartMap: Map<number, number>;
}

const SurahDetailView: React.FC<SurahDetailViewProps> = ({ 
  surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode,
  onSaveAyah, onSearchByAyahNumber,
  currentlyPlayingAyahGlobalNumber, isPlaybackLoading, onStartPlayback,
  allAudioEditions, selectedAudioEdition, onAudioEditionChange,
  simpleCleanData, hizbQuarterStartMap
}) => {
  const highlightRef = useRef<HTMLSpanElement>(null);
  const playingAyahRef = useRef<HTMLSpanElement>(null);
  const wordPopoverRef = useRef<HTMLDivElement>(null);

  const [activePopover, setActivePopover] = useState<{ ayah: Ayah; triggerElement: HTMLElement } | null>(null);
  const [copiedAyah, setCopiedAyah] = useState<number | null>(null);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const [wordPopoverState, setWordPopoverState] = useState<{
    ayahNumberInSurah: number;
    simpleText: string;
    triggerElement: HTMLElement;
  } | null>(null);

  const [touchStartX, setTouchStartX] = useState<number | null>(null);
  const [touchCurrentX, setTouchCurrentX] = useState<number | null>(null);

  const prevSurahNumber = useRef<number | null>(null);

  const { ayahsByPage, firstPage, lastPage, getPageForAyahNumber } = useMemo(() => {
    const map = new Map<number, Ayah[]>();
    const ayahNumToPageMap = new Map<number, number>();
    if (!surah || !surah.ayahs || surah.ayahs.length === 0) {
        return { ayahsByPage: map, firstPage: 1, lastPage: 1, getPageForAyahNumber: (n: number) => undefined };
    }
    let minPage = Infinity;
    let maxPage = -Infinity;
    for (const ayah of surah.ayahs) {
        if (ayah.page) {
            if (!map.has(ayah.page)) {
                map.set(ayah.page, []);
            }
            map.get(ayah.page)!.push(ayah);
            minPage = Math.min(minPage, ayah.page);
            maxPage = Math.max(maxPage, ayah.page);
            ayahNumToPageMap.set(ayah.numberInSurah, ayah.page);
        }
    }
    const getPageForAyahNumber = (num: number) => ayahNumToPageMap.get(num);
    return { ayahsByPage: map, firstPage: minPage === Infinity ? 1 : minPage, lastPage: maxPage === -Infinity ? 1 : maxPage, getPageForAyahNumber };
  }, [surah]);

  useEffect(() => {
    let targetPage: number | undefined;

    if (highlightAyahNumber) {
        targetPage = getPageForAyahNumber(highlightAyahNumber);
    } else if (currentlyPlayingAyahGlobalNumber) {
        const playingAyah = surah.ayahs.find(a => a.number === currentlyPlayingAyahGlobalNumber);
        if (playingAyah) {
            targetPage = getPageForAyahNumber(playingAyah.numberInSurah);
        }
    }

    setCurrentPage(targetPage || firstPage);
  }, [surah.number, highlightAyahNumber, currentlyPlayingAyahGlobalNumber, getPageForAyahNumber, firstPage]);


  useEffect(() => {
    const currentSurahNumber = surah.number;
    const isNewSurahView = prevSurahNumber.current !== currentSurahNumber;

    if (isNewSurahView) {
        prevSurahNumber.current = currentSurahNumber;
    }

    let elementToScroll: HTMLElement | null = null;
    let shouldPulse = false;

    if (currentlyPlayingAyahGlobalNumber !== null && surah.ayahs.some(a => a.number === currentlyPlayingAyahGlobalNumber)) {
        elementToScroll = playingAyahRef.current;
        shouldPulse = false;
    }
    else if (isNewSurahView && highlightAyahNumber) {
        elementToScroll = highlightRef.current;
        shouldPulse = true;
    }

    if (elementToScroll) {
        const scrollTimer = setTimeout(() => {
            elementToScroll?.scrollIntoView({
                behavior: 'smooth',
                block: 'center',
            });

            if (shouldPulse) {
                elementToScroll?.classList.add('animate-highlight-pulse');
                setTimeout(() => {
                    elementToScroll?.classList.remove('animate-highlight-pulse');
                }, 3000);
            }
        }, 150); // Delay to allow page transition to finish

        return () => clearTimeout(scrollTimer);
    } else if (isNewSurahView && browsingMode === 'full') {
        window.scrollTo(0, 0);
    }
  }, [highlightAyahNumber, currentlyPlayingAyahGlobalNumber, surah.number, browsingMode, currentPage]);


  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        const target = event.target as Node;
        if (!(target as HTMLElement).closest('.popover-trigger, .popover-content')) {
            setActivePopover(null);
        }
        if (wordPopoverRef.current && !wordPopoverRef.current.contains(target)) {
            if (!(event.target as HTMLElement).closest('.word-trigger')) {
                setWordPopoverState(null);
            }
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const handlePlaySurah = () => {
    onStartPlayback([], selectedAudioEdition);
  };

  if (displayEdition.format === 'audio') {
    return (
      <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
        <main className="bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300">
          <h3 className="text-xl font-bold mb-4 text-center text-primary-text">{displayEdition.name}</h3>
          <div className="flex flex-col gap-2">
            {surah.ayahs.map(ayah => (
              ayah.audio ? (
                <div key={ayah.number} className="flex items-center gap-4 py-2 px-3 my-1 bg-surface-subtle rounded-lg">
                  <span className="font-bold text-primary-text">الآية {ayah.numberInSurah}</span>
                  <audio
                    controls
                    src={ayah.audio}
                    className="w-full h-10"
                    preload="metadata"
                    title={`الاستماع للآية ${ayah.numberInSurah}`}
                  >
                    متصفحك لا يدعم عنصر الصوت.
                  </audio>
                </div>
              ) : null
            ))}
          </div>
        </main>
      </div>
    );
  }

  const getQuranTextStyle = () => {
    const fallbackFonts = "'Uthman', 'Amiri Quran', 'Tajawal', sans-serif";
    const isImlaei = displayEdition.identifier.includes('simple-clean');

    if (displayEdition.type === 'quran' && displayEdition.direction === 'rtl') {
      return {
        className: `${isImlaei ? 'imlai-font' : 'uthmani-font'} quran-text-${fontSize}`,
        style: {
          fontFamily: `"${selectedFont}", ${fallbackFonts}`,
        }
      };
    }

    return { className: 'font-quran text-2xl', style: {} };
  }

  const { className: quranTextClass, style: quranTextStyle } = getQuranTextStyle();

  const handleSaveClick = (ayah: Ayah) => {
    onSaveAyah({
      type: 'ayah',
      id: `${ayah.surah?.number || surah.number}:${ayah.numberInSurah}`,
      surah: ayah.surah?.number || surah.number,
      ayah: ayah.numberInSurah,
      text: ayah.text || '',
      createdAt: Date.now(),
    });
    setActivePopover(null);
  };

  const handleCopyAyah = (ayah: Ayah) => {
    const surahName = ayah.surah?.name || surah.name;
    const cleanSurahName = formatSurahNameForDisplay(surahName);
    const textToCopy = `"${ayah.text || ''}" (سورة ${cleanSurahName} - الآية ${ayah.numberInSurah})`;
    navigator.clipboard.writeText(textToCopy).then(() => {
        setCopiedAyah(ayah.number);
        setTimeout(() => setCopiedAyah(null), 2000);
        setActivePopover(null);
    });
  };

  const handleSearchByAyahText = (ayah: Ayah) => {
    const simpleSurah = simpleCleanData.find(s => s.number === (ayah.surah?.number || surah.number));
    const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
    const simpleTextToSearch = simpleAyah?.text;

    if (simpleTextToSearch) {
        onWordClick(simpleTextToSearch, 'quran-simple-clean', { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    } else if (ayah.text) {
        onWordClick(ayah.text, displayEdition.identifier, { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    }
    setActivePopover(null);
  };

  const handlePlayFromAyah = (ayah: Ayah) => {
    const startIndex = surah.ayahs.findIndex(a => a.numberInSurah === ayah.numberInSurah);
    if (startIndex !== -1) {
        onStartPlayback([], selectedAudioEdition, startIndex);
    }
    setActivePopover(null);
  };

  const handleNextPage = () => {
    setCurrentPage(p => {
        const nextPage = p < lastPage ? p + 1 : p;
        if (nextPage !== p) window.scrollTo({ top: 0, behavior: 'smooth' });
        return nextPage;
    });
  };

  const handlePrevPage = () => {
      setCurrentPage(p => {
          const prevPage = p > firstPage ? p - 1 : p;
          if (prevPage !== p) window.scrollTo({ top: 0, behavior: 'smooth' });
          return prevPage;
      });
  };

  const SWIPE_THRESHOLD = 50;

  const handleTouchStart = (e: React.TouchEvent) => {
      if (browsingMode !== 'page') return;
      setTouchStartX(e.targetTouches[0].clientX);
      setTouchCurrentX(e.targetTouches[0].clientX);
  };

  const handleTouchMove = (e: React.TouchEvent) => {
      if (touchStartX === null || browsingMode !== 'page') return;
      setTouchCurrentX(e.targetTouches[0].clientX);
  };

  const handleTouchEnd = () => {
      if (touchStartX === null || touchCurrentX === null || browsingMode !== 'page') return;

      const deltaX = touchStartX - touchCurrentX;

      if (Math.abs(deltaX) > SWIPE_THRESHOLD) {
          if (deltaX > 0) { 
              if (currentPage < lastPage) {
                  handleNextPage();
              }
          } else { 
              if (currentPage > firstPage) {
                  handlePrevPage();
              }
          }
      }

      setTouchStartX(null);
      setTouchCurrentX(null);
  };

  const swipeTranslateX = useMemo(() => {
      if (touchStartX === null || touchCurrentX === null || browsingMode !== 'page') {
          return 0;
      }
      const deltaX = touchCurrentX - touchStartX;

      if ((deltaX < 0 && currentPage >= lastPage) || (deltaX > 0 && currentPage <= firstPage)) {
          return deltaX / 3;
      }
      return deltaX;
  }, [touchStartX, touchCurrentX, browsingMode, currentPage, firstPage, lastPage]);

  const ayahsToRender = useMemo(() => browsingMode === 'page'
      ? (ayahsByPage.get(currentPage) || [])
      : surah.ayahs, [browsingMode, ayahsByPage, currentPage, surah.ayahs]);

  const pageInfo = useMemo(() => {
    if (browsingMode !== 'page' || !hizbQuarterStartMap || ayahsToRender.length === 0) return null;

    const firstAyah = ayahsToRender[0];
    let surahName = firstAyah.surah?.name || surah.name;
    surahName = surahName.replace(/^سُورَةُ\s*/, '').trim();

    const juzNumber = firstAyah.juz;
    const hizbNumber = firstAyah.hizbQuarter ? Math.floor((firstAyah.hizbQuarter - 1) / 4) + 1 : null;

    const markers: {label: string}[] = [];
    const processedQuarters = new Set<number>();

    if (hizbNumber) {
        const startOfHizbQuarter = (hizbNumber - 1) * 4 + 1;
        if(hizbQuarterStartMap.get(startOfHizbQuarter) === firstAyah.number) {
            markers.push({ label: `الحزب ${hizbNumber}`});
        }
    }

    for(const ayah of ayahsToRender) {
        if(ayah.hizbQuarter && hizbQuarterStartMap.get(ayah.hizbQuarter) === ayah.number) {
            if (processedQuarters.has(ayah.hizbQuarter)) continue;

            const quarterType = (ayah.hizbQuarter - 1) % 4;
            if (quarterType === 1) markers.push({ label: 'ربع الحزب'});
            else if (quarterType === 2) markers.push({ label: 'نصف الحزب'});
            else if (quarterType === 3) markers.push({ label: 'ثلاثة أرباع الحزب'});

            processedQuarters.add(ayah.hizbQuarter);
        }
    }

    return {
        surahName,
        juzNumber,
        markers,
        side: currentPage % 2 === 0 ? 'left' : 'right'
    };
  }, [currentPage, browsingMode, ayahsToRender, hizbQuarterStartMap, surah.name]);

  const isBismillahApplicable = surah.number !== 1 && surah.number !== 9 && displayEdition.type === 'quran' && displayEdition.direction === 'rtl';

  // FIX: Add a defensive check to prevent duplicate Bismillah.
  const firstAyahTextOnPage = ayahsToRender[0]?.text || '';
  const firstAyahOnPageHasBismillah = /^بِسْمِ ٱللَّهِ/.test(firstAyahTextOnPage);

  const shouldShowBismillah = isBismillahApplicable && !firstAyahOnPageHasBismillah && (browsingMode === 'full' || (browsingMode === 'page' && currentPage === firstPage));

  return (
    <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
      {displayEdition.type === 'quran' && displayEdition.direction === 'rtl' && (
        <div className="w-full max-w-4xl mx-auto mb-4 flex items-stretch justify-center gap-3">
            <div className="flex-grow">
                <AudioEditionSelector
                    audioEditions={allAudioEditions}
                    selectedAudioEdition={selectedAudioEdition}
                    onSelect={onAudioEditionChange}
                />
            </div>
            <button
                onClick={handlePlaySurah}
                disabled={isPlaybackLoading || allAudioEditions.length === 0}
                className="flex items-center gap-3 px-6 py-3 bg-surface border-2 border-primary text-primary-text rounded-lg shadow-sm hover:shadow-md hover:bg-surface-hover transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary disabled:opacity-60 disabled:cursor-not-allowed flex-shrink-0"
                aria-label="استماع للسورة"
            >
                {isPlaybackLoading ? <SpinnerIcon className="w-6 h-6"/> : <PlayIcon className="w-6 h-6"/>}
                <span className="text-lg font-semibold hidden sm:inline">{isPlaybackLoading ? 'جاري التحضير...' : 'استماع'}</span>
            </button>
        </div>
      )}
      <div className="overflow-hidden rounded-lg">
        {browsingMode === 'page' && !displayEdition.identifier.includes('simple-clean') ? (
             <div
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    transform: `translateX(${swipeTranslateX}px)`,
                    transition: touchStartX === null ? 'transform 0.3s ease-out' : 'none',
                }}
             >
                <div className="mushaf-page" style={{ touchAction: 'pan-y' }}>
                    {pageInfo?.markers.map((marker, index) => (
                         <div key={index} className={`hizb-marker ${pageInfo.side}`}>{marker.label}</div>
                    ))}
                    <header className="mushaf-header">
                        <span>{pageInfo?.juzNumber && `الجزء ${pageInfo.juzNumber}`}</span>
                        <span>{pageInfo?.surahName && `سورة ${pageInfo.surahName}`}</span>
                    </header>

                    {shouldShowBismillah && (
                        <div className="text-center mb-8 font-bismillah text-2xl text-primary-text-strong">
                            بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ
                        </div>
                    )}
                    <main dir={displayEdition.direction} style={quranTextStyle} className={`text-text-primary ${quranTextClass} text-justify`}>
                        <AyahRenderer {...{ ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode, currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState, setActivePopover, playingAyahRef, highlightRef }} />
                    </main>

                    <footer className="mushaf-footer">
                        <span>{currentPage}</span>
                    </footer>
                </div>
            </div>
        ) : (
            <main
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    transform: `translateX(${swipeTranslateX}px)`,
                    transition: touchStartX === null ? 'transform 0.3s ease-out' : 'none',
                    touchAction: browsingMode === 'page' ? 'pan-y' : 'auto',
                }}
                className={`bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300 ${browsingMode === 'page' ? 'cursor-grab active:cursor-grabbing' : ''}`}
            >
                {browsingMode === 'page' && lastPage > firstPage && (
                    <div className="text-center mb-6 -mt-2">
                        <span className="font-mono text-sm font-semibold text-text-muted select-none">
                            {currentPage}
                        </span>
                    </div>
                )}
                {shouldShowBismillah && (
                    <div className="text-center mb-8 font-bismillah text-2xl text-primary-text-strong">
                        بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ
                    </div>
                )}
                <div dir={displayEdition.direction} style={quranTextStyle} className={`text-text-primary ${quranTextClass} ${displayEdition.direction === 'ltr' ? 'text-left' : 'text-right'}`}>
                     <AyahRenderer {...{ ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode, currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState, setActivePopover, playingAyahRef, highlightRef }} />
                </div>
            </main>
        )}
      </div>

      {browsingMode === 'page' && lastPage > firstPage && (
          <div className="mt-6 flex items-center justify-between p-2 bg-surface rounded-full shadow-md border border-border-default">
              <button 
                  onClick={handlePrevPage} 
                  disabled={currentPage <= firstPage}
                  className="flex items-center gap-2 px-4 py-2 rounded-full text-text-secondary hover:bg-surface-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                  <ArrowRightIcon className="w-5 h-5" />
                  <span className="font-semibold hidden sm:inline">الصفحة السابقة</span>
              </button>
              <div className="font-bold text-lg text-text-primary font-mono select-none">
                  {currentPage}
              </div>
              <button 
                  onClick={handleNextPage} 
                  disabled={currentPage >= lastPage}
                  className="flex items-center gap-2 px-4 py-2 rounded-full text-text-secondary hover:bg-surface-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                  <span className="font-semibold hidden sm:inline">الصفحة التالية</span>
                  <ArrowLeftIcon className="w-5 h-5" />
              </button>
          </div>
      )}

      {wordPopoverState && (
         <div 
            ref={wordPopoverRef}
            className="absolute p-3 bg-surface rounded-lg shadow-lg border border-border-default flex items-center gap-2 z-20 animate-fade-in flex-wrap leading-loose"
            style={(() => {
                if (!wordPopoverState.triggerElement) return { opacity: 0, top: 0, left: 0 };
                const rect = wordPopoverState.triggerElement.getBoundingClientRect();
                return {
                    top: `${rect.bottom + window.scrollY + 5}px`,
                    left: `${rect.left + window.scrollX + rect.width / 2}px`,
                    transform: 'translateX(-50%)',
                };
            })()}
        >
            {wordPopoverState.simpleText.split(' ').map((word, index) => (
                <button
                    key={index}
                    onClick={() => {
                        onWordClick(word, 'quran-simple-clean', { surah: surah.number, ayah: wordPopoverState.ayahNumberInSurah, wordIndex: index });
                        setWordPopoverState(null);
                    }}
                    className="px-2 py-1 bg-surface-subtle rounded-md hover:bg-primary/20 transition-colors"
                >
                    {word}
                </button>
            ))}
        </div>
      )}

      {activePopover && (
        <AyahActionPopover 
            activePopover={activePopover}
            onClose={() => setActivePopover(null)}
            onSave={handleSaveClick}
            onCopy={handleCopyAyah}
            onSearchText={handleSearchByAyahText}
            onSearchNumber={onSearchByAyahNumber}
            onPlayFrom={handlePlayFromAyah}
            copiedAyah={copiedAyah}
        />
      )}

    </div>
  );
};

export default SurahDetailView;

import React, { useEffect, useRef, useState, useMemo } from 'react';
import type { SurahData, QuranEdition, QuranFont, SavedAyahItem, Ayah, FontSize, BrowsingMode } from '../types';
import { PlayIcon, SpinnerIcon, ArrowLeftIcon, ArrowRightIcon } from './icons';
import AudioEditionSelector from './AudioEditionSelector';
import AyahActionPopover from './AyahActionPopover';
import AyahRenderer from './AyahRenderer';
import { formatSurahNameForDisplay, normalizeArabicText } from '../utils/text';

interface SurahDetailViewProps {
  surah: SurahData;
  highlightAyahNumber: number | null;
  onWordClick: (query: string, editionIdentifier: string, position: { surah: number; ayah: number; wordIndex: number; }) => void;
  displayEdition: QuranEdition;
  selectedFont: string;
  fontSize: FontSize;
  browsingMode: BrowsingMode;
  onSaveAyah: (item: SavedAyahItem) => void;
  onSearchByAyahNumber: (ayahNumber: number) => void;
  // --- Props for audio playback ---
  currentlyPlayingAyahGlobalNumber: number | null;
  isPlaybackLoading: boolean;
  onStartPlayback: (ayahs: Ayah[], audioEditionIdentifier: string, startIndex?: number) => void;
  allAudioEditions: QuranEdition[];
  selectedAudioEdition: string;
  onAudioEditionChange: (identifier: string) => void;
  // --- Prop for word popover ---
  simpleCleanData: SurahData[];
  hizbQuarterStartMap: Map<number, number>;
}

const SurahDetailView: React.FC<SurahDetailViewProps> = ({ 
  surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode,
  onSaveAyah, onSearchByAyahNumber,
  currentlyPlayingAyahGlobalNumber, isPlaybackLoading, onStartPlayback,
  allAudioEditions, selectedAudioEdition, onAudioEditionChange,
  simpleCleanData, hizbQuarterStartMap
}) => {
  const highlightRef = useRef<HTMLSpanElement>(null);
  const playingAyahRef = useRef<HTMLSpanElement>(null);
  const wordPopoverRef = useRef<HTMLDivElement>(null);

  const [activePopover, setActivePopover] = useState<{ ayah: Ayah; triggerElement: HTMLElement } | null>(null);
  const [copiedAyah, setCopiedAyah] = useState<number | null>(null);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const [wordPopoverState, setWordPopoverState] = useState<{
    ayahNumberInSurah: number;
    simpleText: string;
    triggerElement: HTMLElement;
  } | null>(null);

  const [touchStartX, setTouchStartX] = useState<number | null>(null);
  const [touchCurrentX, setTouchCurrentX] = useState<number | null>(null);

  const prevSurahNumber = useRef<number | null>(null);

  const { ayahsByPage, firstPage, lastPage, getPageForAyahNumber } = useMemo(() => {
    const map = new Map<number, Ayah[]>();
    const ayahNumToPageMap = new Map<number, number>();
    if (!surah || !surah.ayahs || surah.ayahs.length === 0) {
        return { ayahsByPage: map, firstPage: 1, lastPage: 1, getPageForAyahNumber: (n: number) => undefined };
    }
    let minPage = Infinity;
    let maxPage = -Infinity;
    for (const ayah of surah.ayahs) {
        if (ayah.page) {
            if (!map.has(ayah.page)) {
                map.set(ayah.page, []);
            }
            map.get(ayah.page)!.push(ayah);
            minPage = Math.min(minPage, ayah.page);
            maxPage = Math.max(maxPage, ayah.page);
            ayahNumToPageMap.set(ayah.numberInSurah, ayah.page);
        }
    }
    const getPageForAyahNumber = (num: number) => ayahNumToPageMap.get(num);
    return { ayahsByPage: map, firstPage: minPage === Infinity ? 1 : minPage, lastPage: maxPage === -Infinity ? 1 : maxPage, getPageForAyahNumber };
  }, [surah]);

  useEffect(() => {
    let targetPage: number | undefined;

    if (highlightAyahNumber) {
        targetPage = getPageForAyahNumber(highlightAyahNumber);
    } else if (currentlyPlayingAyahGlobalNumber) {
        const playingAyah = surah.ayahs.find(a => a.number === currentlyPlayingAyahGlobalNumber);
        if (playingAyah) {
            targetPage = getPageForAyahNumber(playingAyah.numberInSurah);
        }
    }

    setCurrentPage(targetPage || firstPage);
  }, [surah.number, highlightAyahNumber, currentlyPlayingAyahGlobalNumber, getPageForAyahNumber, firstPage]);


  useEffect(() => {
    const currentSurahNumber = surah.number;
    const isNewSurahView = prevSurahNumber.current !== currentSurahNumber;

    if (isNewSurahView) {
        prevSurahNumber.current = currentSurahNumber;
    }

    let elementToScroll: HTMLElement | null = null;
    let shouldPulse = false;

    if (currentlyPlayingAyahGlobalNumber !== null && surah.ayahs.some(a => a.number === currentlyPlayingAyahGlobalNumber)) {
        elementToScroll = playingAyahRef.current;
        shouldPulse = false;
    }
    else if (isNewSurahView && highlightAyahNumber) {
        elementToScroll = highlightRef.current;
        shouldPulse = true;
    }

    if (elementToScroll) {
        const scrollTimer = setTimeout(() => {
            elementToScroll?.scrollIntoView({
                behavior: 'smooth',
                block: 'center',
            });

            if (shouldPulse) {
                elementToScroll?.classList.add('animate-highlight-pulse');
                setTimeout(() => {
                    elementToScroll?.classList.remove('animate-highlight-pulse');
                }, 3000);
            }
        }, 150); // Delay to allow page transition to finish

        return () => clearTimeout(scrollTimer);
    } else if (isNewSurahView && browsingMode === 'full') {
        window.scrollTo(0, 0);
    }
  }, [highlightAyahNumber, currentlyPlayingAyahGlobalNumber, surah.number, browsingMode, currentPage]);


  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        const target = event.target as Node;
        if (!(target as HTMLElement).closest('.popover-trigger, .popover-content')) {
            setActivePopover(null);
        }
        if (wordPopoverRef.current && !wordPopoverRef.current.contains(target)) {
            if (!(event.target as HTMLElement).closest('.word-trigger')) {
                setWordPopoverState(null);
            }
        }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => {
        document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  const handlePlaySurah = () => {
    onStartPlayback([], selectedAudioEdition);
  };

  if (displayEdition.format === 'audio') {
    return (
      <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
        <main className="bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300">
          <h3 className="text-xl font-bold mb-4 text-center text-primary-text">{displayEdition.name}</h3>
          <div className="flex flex-col gap-2">
            {surah.ayahs.map(ayah => (
              ayah.audio ? (
                <div key={ayah.number} className="flex items-center gap-4 py-2 px-3 my-1 bg-surface-subtle rounded-lg">
                  <span className="font-bold text-primary-text">الآية {ayah.numberInSurah}</span>
                  <audio
                    controls
                    src={ayah.audio}
                    className="w-full h-10"
                    preload="metadata"
                    title={`الاستماع للآية ${ayah.numberInSurah}`}
                  >
                    متصفحك لا يدعم عنصر الصوت.
                  </audio>
                </div>
              ) : null
            ))}
          </div>
        </main>
      </div>
    );
  }

  const getQuranTextStyle = () => {
    const fallbackFonts = "'Uthman', 'Amiri Quran', 'Tajawal', sans-serif";
    const isImlaei = displayEdition.identifier.includes('simple-clean');

    if (displayEdition.type === 'quran' && displayEdition.direction === 'rtl') {
      return {
        className: `${isImlaei ? 'imlai-font' : 'uthmani-font'} quran-text-${fontSize}`,
        style: {
          fontFamily: `"${selectedFont}", ${fallbackFonts}`,
        }
      };
    }

    return { className: 'font-quran text-2xl', style: {} };
  }

  const { className: quranTextClass, style: quranTextStyle } = getQuranTextStyle();

  const handleSaveClick = (ayah: Ayah) => {
    onSaveAyah({
      type: 'ayah',
      id: `${ayah.surah?.number || surah.number}:${ayah.numberInSurah}`,
      surah: ayah.surah?.number || surah.number,
      ayah: ayah.numberInSurah,
      text: ayah.text || '',
      createdAt: Date.now(),
    });
    setActivePopover(null);
  };

  const handleCopyAyah = (ayah: Ayah) => {
    const surahName = ayah.surah?.name || surah.name;
    const cleanSurahName = formatSurahNameForDisplay(surahName);
    const textToCopy = `"${ayah.text || ''}" (سورة ${cleanSurahName} - الآية ${ayah.numberInSurah})`;
    navigator.clipboard.writeText(textToCopy).then(() => {
        setCopiedAyah(ayah.number);
        setTimeout(() => setCopiedAyah(null), 2000);
        setActivePopover(null);
    });
  };

  const handleSearchByAyahText = (ayah: Ayah) => {
    const simpleSurah = simpleCleanData.find(s => s.number === (ayah.surah?.number || surah.number));
    const simpleAyah = simpleSurah?.ayahs.find(a => a.numberInSurah === ayah.numberInSurah);
    const simpleTextToSearch = simpleAyah?.text;

    if (simpleTextToSearch) {
        onWordClick(simpleTextToSearch, 'quran-simple-clean', { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    } else if (ayah.text) {
        onWordClick(ayah.text, displayEdition.identifier, { surah: surah.number, ayah: ayah.numberInSurah, wordIndex: 0 });
    }
    setActivePopover(null);
  };

  const handlePlayFromAyah = (ayah: Ayah) => {
    const startIndex = surah.ayahs.findIndex(a => a.numberInSurah === ayah.numberInSurah);
    if (startIndex !== -1) {
        onStartPlayback([], selectedAudioEdition, startIndex);
    }
    setActivePopover(null);
  };

  const handleNextPage = () => {
    setCurrentPage(p => {
        const nextPage = p < lastPage ? p + 1 : p;
        if (nextPage !== p) window.scrollTo({ top: 0, behavior: 'smooth' });
        return nextPage;
    });
  };

  const handlePrevPage = () => {
      setCurrentPage(p => {
          const prevPage = p > firstPage ? p - 1 : p;
          if (prevPage !== p) window.scrollTo({ top: 0, behavior: 'smooth' });
          return prevPage;
      });
  };

  const SWIPE_THRESHOLD = 50;

  const handleTouchStart = (e: React.TouchEvent) => {
      if (browsingMode !== 'page') return;
      setTouchStartX(e.targetTouches[0].clientX);
      setTouchCurrentX(e.targetTouches[0].clientX);
  };

  const handleTouchMove = (e: React.TouchEvent) => {
      if (touchStartX === null || browsingMode !== 'page') return;
      setTouchCurrentX(e.targetTouches[0].clientX);
  };

  const handleTouchEnd = () => {
      if (touchStartX === null || touchCurrentX === null || browsingMode !== 'page') return;

      const deltaX = touchStartX - touchCurrentX;

      if (Math.abs(deltaX) > SWIPE_THRESHOLD) {
          if (deltaX > 0) { 
              if (currentPage < lastPage) {
                  handleNextPage();
              }
          } else { 
              if (currentPage > firstPage) {
                  handlePrevPage();
              }
          }
      }

      setTouchStartX(null);
      setTouchCurrentX(null);
  };

  const swipeTranslateX = useMemo(() => {
      if (touchStartX === null || touchCurrentX === null || browsingMode !== 'page') {
          return 0;
      }
      const deltaX = touchCurrentX - touchStartX;

      if ((deltaX < 0 && currentPage >= lastPage) || (deltaX > 0 && currentPage <= firstPage)) {
          return deltaX / 3;
      }
      return deltaX;
  }, [touchStartX, touchCurrentX, browsingMode, currentPage, firstPage, lastPage]);

  const ayahsToRender = useMemo(() => browsingMode === 'page'
      ? (ayahsByPage.get(currentPage) || [])
      : surah.ayahs, [browsingMode, ayahsByPage, currentPage, surah.ayahs]);

  const pageInfo = useMemo(() => {
    if (browsingMode !== 'page' || !hizbQuarterStartMap || ayahsToRender.length === 0) return null;

    const firstAyah = ayahsToRender[0];
    let surahName = firstAyah.surah?.name || surah.name;
    surahName = surahName.replace(/^سُورَةُ\s*/, '').trim();

    const juzNumber = firstAyah.juz;
    const hizbNumber = firstAyah.hizbQuarter ? Math.floor((firstAyah.hizbQuarter - 1) / 4) + 1 : null;

    const markers: {label: string}[] = [];
    const processedQuarters = new Set<number>();

    if (hizbNumber) {
        const startOfHizbQuarter = (hizbNumber - 1) * 4 + 1;
        if(hizbQuarterStartMap.get(startOfHizbQuarter) === firstAyah.number) {
            markers.push({ label: `الحزب ${hizbNumber}`});
        }
    }

    for(const ayah of ayahsToRender) {
        if(ayah.hizbQuarter && hizbQuarterStartMap.get(ayah.hizbQuarter) === ayah.number) {
            if (processedQuarters.has(ayah.hizbQuarter)) continue;

            const quarterType = (ayah.hizbQuarter - 1) % 4;
            if (quarterType === 1) markers.push({ label: 'ربع الحزب'});
            else if (quarterType === 2) markers.push({ label: 'نصف الحزب'});
            else if (quarterType === 3) markers.push({ label: 'ثلاثة أرباع الحزب'});

            processedQuarters.add(ayah.hizbQuarter);
        }
    }

    return {
        surahName,
        juzNumber,
        markers,
        side: currentPage % 2 === 0 ? 'left' : 'right'
    };
  }, [currentPage, browsingMode, ayahsToRender, hizbQuarterStartMap, surah.name]);

  const isBismillahApplicable = surah.number !== 1 && surah.number !== 9 && displayEdition.type === 'quran' && displayEdition.direction === 'rtl';

  const firstAyahTextOnPage = ayahsToRender[0]?.text || '';
  const normalizedFirstAyahText = normalizeArabicText(firstAyahTextOnPage);
  const firstAyahOnPageHasBismillah = normalizedFirstAyahText.startsWith('بسم الله الرحمن الرحيم');

  const shouldShowBismillah = isBismillahApplicable && !firstAyahOnPageHasBismillah && (browsingMode === 'full' || (browsingMode === 'page' && currentPage === firstPage));

  return (
    <div className="animate-fade-in w-full max-w-4xl mx-auto px-4">
      {displayEdition.type === 'quran' && displayEdition.direction === 'rtl' && (
        <div className="w-full max-w-4xl mx-auto mb-4 flex items-stretch justify-center gap-3">
            <div className="flex-grow">
                <AudioEditionSelector
                    audioEditions={allAudioEditions}
                    selectedAudioEdition={selectedAudioEdition}
                    onSelect={onAudioEditionChange}
                />
            </div>
            <button
                onClick={handlePlaySurah}
                disabled={isPlaybackLoading || allAudioEditions.length === 0}
                className="flex items-center gap-3 px-6 py-3 bg-surface border-2 border-primary text-primary-text rounded-lg shadow-sm hover:shadow-md hover:bg-surface-hover transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary disabled:opacity-60 disabled:cursor-not-allowed flex-shrink-0"
                aria-label="استماع للسورة"
            >
                {isPlaybackLoading ? <SpinnerIcon className="w-6 h-6"/> : <PlayIcon className="w-6 h-6"/>}
                <span className="text-lg font-semibold hidden sm:inline">{isPlaybackLoading ? 'جاري التحضير...' : 'استماع'}</span>
            </button>
        </div>
      )}
      <div className="overflow-hidden rounded-lg">
        {browsingMode === 'page' && !displayEdition.identifier.includes('simple-clean') ? (
             <div
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    transform: `translateX(${swipeTranslateX}px)`,
                    transition: touchStartX === null ? 'transform 0.3s ease-out' : 'none',
                }}
             >
                <div className="mushaf-page" style={{ touchAction: 'pan-y' }}>
                    {pageInfo?.markers.map((marker, index) => (
                         <div key={index} className={`hizb-marker ${pageInfo.side}`}>{marker.label}</div>
                    ))}
                    <header className="mushaf-header">
                        <span>{pageInfo?.juzNumber && `الجزء ${pageInfo.juzNumber}`}</span>
                        <span>{pageInfo?.surahName && `سورة ${pageInfo.surahName}`}</span>
                    </header>

                    {shouldShowBismillah && (
                        <div className="text-center mb-8 font-bismillah text-2xl text-primary-text-strong">
                            بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ
                        </div>
                    )}
                    <main dir={displayEdition.direction} style={quranTextStyle} className={`text-text-primary ${quranTextClass} text-justify`}>
                        <AyahRenderer {...{ ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode, currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState, setActivePopover, playingAyahRef, highlightRef }} />
                    </main>

                    <footer className="mushaf-footer">
                        <span>{currentPage}</span>
                    </footer>
                </div>
            </div>
        ) : (
            <main
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
                style={{
                    transform: `translateX(${swipeTranslateX}px)`,
                    transition: touchStartX === null ? 'transform 0.3s ease-out' : 'none',
                    touchAction: browsingMode === 'page' ? 'pan-y' : 'auto',
                }}
                className={`bg-surface p-6 sm:p-8 rounded-lg shadow-md transition-colors duration-300 ${browsingMode === 'page' ? 'cursor-grab active:cursor-grabbing' : ''}`}
            >
                {browsingMode === 'page' && lastPage > firstPage && (
                    <div className="text-center mb-6 -mt-2">
                        <span className="font-mono text-sm font-semibold text-text-muted select-none">
                            {currentPage}
                        </span>
                    </div>
                )}
                {shouldShowBismillah && (
                    <div className="text-center mb-8 font-bismillah text-2xl text-primary-text-strong">
                        بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ
                    </div>
                )}
                <div dir={displayEdition.direction} style={quranTextStyle} className={`text-text-primary ${quranTextClass} ${displayEdition.direction === 'ltr' ? 'text-left' : 'text-right'}`}>
                     <AyahRenderer {...{ ayahsToRender, surah, highlightAyahNumber, onWordClick, displayEdition, selectedFont, fontSize, browsingMode, currentlyPlayingAyahGlobalNumber, simpleCleanData, wordPopoverState, setWordPopoverState, setActivePopover, playingAyahRef, highlightRef }} />
                </div>
            </main>
        )}
      </div>

      {browsingMode === 'page' && lastPage > firstPage && (
          <div className="mt-6 flex items-center justify-between p-2 bg-surface rounded-full shadow-md border border-border-default">
              <button 
                  onClick={handlePrevPage} 
                  disabled={currentPage <= firstPage}
                  className="flex items-center gap-2 px-4 py-2 rounded-full text-text-secondary hover:bg-surface-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                  <ArrowRightIcon className="w-5 h-5" />
                  <span className="font-semibold hidden sm:inline">الصفحة السابقة</span>
              </button>
              <div className="font-bold text-lg text-text-primary font-mono select-none">
                  {currentPage}
              </div>
              <button 
                  onClick={handleNextPage} 
                  disabled={currentPage >= lastPage}
                  className="flex items-center gap-2 px-4 py-2 rounded-full text-text-secondary hover:bg-surface-hover disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                  <span className="font-semibold hidden sm:inline">الصفحة التالية</span>
                  <ArrowLeftIcon className="w-5 h-5" />
              </button>
          </div>
      )}

      {wordPopoverState && (
         <div 
            ref={wordPopoverRef}
            className="absolute p-3 bg-surface rounded-lg shadow-lg border border-border-default flex items-center gap-2 z-20 animate-fade-in flex-wrap leading-loose"
            style={(() => {
                if (!wordPopoverState.triggerElement) return { opacity: 0, top: 0, left: 0 };
                const rect = wordPopoverState.triggerElement.getBoundingClientRect();
                return {
                    top: `${rect.bottom + window.scrollY + 5}px`,
                    left: `${rect.left + window.scrollX + rect.width / 2}px`,
                    transform: 'translateX(-50%)',
                };
            })()}
        >
            {wordPopoverState.simpleText.split(' ').map((word, index) => (
                <button
                    key={index}
                    onClick={() => {
                        onWordClick(word, 'quran-simple-clean', { surah: surah.number, ayah: wordPopoverState.ayahNumberInSurah, wordIndex: index });
                        setWordPopoverState(null);
                    }}
                    className="px-2 py-1 bg-surface-subtle rounded-md hover:bg-primary/20 transition-colors"
                >
                    {word}
                </button>
            ))}
        </div>
      )}

      {activePopover && (
        <AyahActionPopover 
            activePopover={activePopover}
            onClose={() => setActivePopover(null)}
            onSave={handleSaveClick}
            onCopy={handleCopyAyah}
            onSearchText={handleSearchByAyahText}
            onSearchNumber={onSearchByAyahNumber}
            onPlayFrom={handlePlayFromAyah}
            copiedAyah={copiedAyah}
        />
      )}

    </div>
  );
};

export default SurahDetailView;

import { useState, useEffect, useCallback, useMemo } from 'react';
import type { QuranEdition, QuranFont, FontSize, BrowsingMode } from '../types';

const QURAN_EDITION_KEY = 'qran_app_edition';
const ACTIVE_EDITIONS_KEY = 'qran_app_active_editions';
const FONT_KEY = 'qran_app_selected_font';
const FONT_SIZE_KEY = 'qran_app_font_size';
const AUDIO_EDITION_KEY = 'qran_app_audio_edition';
const BROWSING_MODE_KEY = 'qran_app_browsing_mode';

const DEFAULT_EDITIONS: QuranEdition[] = [
    { identifier: "quran-simple-clean", language: "ar", name: "المصحف الشريف المبسط (بدون تشكيل)", englishName: "Simple Clean", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" },
    { identifier: "quran-uthmani", language: "ar", name: "المصحف الشريف برسم العثماني", englishName: "Uthmani", format: "text", type: "quran", direction: "rtl", sourceApi: "alquran.cloud" }
];

export const useSettings = (
    availableEditions: QuranEdition[], 
    fetchCustomEditionData: (identifier: string) => void
) => {
    const [selectedFontFamily, setSelectedFontFamily] = useState<string>(() => localStorage.getItem(FONT_KEY) || 'Amiri Quran');
    const [fontSize, setFontSize] = useState<FontSize>(() => (localStorage.getItem(FONT_SIZE_KEY) as FontSize) || 'md');

    const [selectedEdition, setSelectedEdition] = useState<string>(
        () => localStorage.getItem(QURAN_EDITION_KEY) || 'quran-simple-clean'
    );

    const [browsingMode, setBrowsingMode] = useState<BrowsingMode>(() => {
        const storedMode = localStorage.getItem(BROWSING_MODE_KEY) as BrowsingMode;
        if (storedMode) return storedMode;
        return selectedEdition === 'quran-uthmani' ? 'page' : 'full';
    });

    const [activeEditions, setActiveEditions] = useState<QuranEdition[]>(() => {
        try {
            const stored = localStorage.getItem(ACTIVE_EDITIONS_KEY);
            const editions = stored ? JSON.parse(stored) : DEFAULT_EDITIONS;

            const simpleUthmani = availableEditions.find(e => e.identifier === 'quran-uthmani-simple');
            if (simpleUthmani && !editions.some((e: any) => e.identifier === 'quran-uthmani-simple')) {
                editions.push(simpleUthmani);
            }
            return editions;
        } catch (e) {
            console.error("Failed to parse active editions from localStorage", e);
            return DEFAULT_EDITIONS;
        }
    });

    const [selectedAudioEdition, setSelectedAudioEdition] = useState<string>(
        () => localStorage.getItem(AUDIO_EDITION_KEY) || 'ar.alafasy'
    );

    useEffect(() => { localStorage.setItem(QURAN_EDITION_KEY, selectedEdition); }, [selectedEdition]);
    useEffect(() => { localStorage.setItem(ACTIVE_EDITIONS_KEY, JSON.stringify(activeEditions)); }, [activeEditions]);
    useEffect(() => { localStorage.setItem(FONT_KEY, selectedFontFamily); }, [selectedFontFamily]);
    useEffect(() => { localStorage.setItem(FONT_SIZE_KEY, fontSize); }, [fontSize]);
    useEffect(() => { localStorage.setItem(BROWSING_MODE_KEY, browsingMode); }, [browsingMode]);
    useEffect(() => { localStorage.setItem(AUDIO_EDITION_KEY, selectedAudioEdition); }, [selectedAudioEdition]);

    const handleAddEdition = useCallback((identifier: string) => {
        if (activeEditions.some(e => e.identifier === identifier)) {
            alert("هذا المصدر مضاف بالفعل.");
            return;
        }

        const editionToAdd = availableEditions.find(e => e.identifier === identifier);
        let newEdition: QuranEdition;

        if (editionToAdd) {
            newEdition = editionToAdd;
        } else if (identifier.startsWith('http')) {
            let hostname: string;
            try { hostname = new URL(identifier).hostname; } 
            catch (e) {
                alert("الرابط المدخل غير صالح.");
                return;
            }
            newEdition = {
                identifier: identifier, language: 'ar', name: `مصدر مخصص (${hostname})`,
                englishName: 'Custom Source', format: 'text', type: 'quran', direction: 'rtl', sourceApi: 'manual',
            };
        } else {
            alert("لم يتم العثور على المصدر المطلوب.");
            return;
        }

        setActiveEditions(prev => [...prev, newEdition]);
        fetchCustomEditionData(newEdition.identifier);
    }, [activeEditions, availableEditions, fetchCustomEditionData]);

    const handleDeleteEdition = useCallback((identifier: string) => {
        if (identifier === 'quran-simple-clean' || identifier === 'quran-uthmani') {
            alert("لا يمكن حذف المصادر الأساسية.");
            return;
        }
        setActiveEditions(prev => {
            const newEditions = prev.filter(e => e.identifier !== identifier);
            if (selectedEdition === identifier) setSelectedEdition('quran-simple-clean');
            return newEditions;
        });
    }, [selectedEdition]);

    const displayEdition = useMemo(() => {
        const found = activeEditions.find(e => e.identifier === selectedEdition) || availableEditions.find(e => e.identifier === selectedEdition) || DEFAULT_EDITIONS[0];
        if (found.name.includes('القرآن الكريم')) {
            return { ...found, name: found.name.replace(/القرآن الكريم/g, 'المصحف الشريف') };
        }
        return found;
    }, [activeEditions, selectedEdition, availableEditions]);

    return {
        selectedFontFamily, setSelectedFontFamily,
        fontSize, setFontSize,
        browsingMode, setBrowsingMode,
        activeEditions,
        selectedEdition, setSelectedEdition,
        selectedAudioEdition, setSelectedAudioEdition,
        handleAddEdition,
        handleDeleteEdition,
        displayEdition
    };
};

