export const useQuranData = () => {
    const [allQuranData, setAllQuranData] = useState<{ [key: string]: SurahData[] } | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isBackgroundLoading, setIsBackgroundLoading] = useState(false);
    const [loadingEditions, setLoadingEditions] = useState<string[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [dataSourceStatus, setDataSourceStatus] = useState<'primary' | 'fallback'>('primary');
    const [availableFonts, setAvailableFonts] = useState<QuranFont[]>(DEFAULT_FONTS);
    const [availableEditions, setAvailableEditions] = useState<QuranEdition[]>(FULL_DEFAULT_EDITIONS);

    const getEditionUrl = useCallback((edition: QuranEdition): string => {
        const { identifier, sourceApi } = edition;
        if (identifier === 'quran-simple-clean') return 'https://storage.googleapis.com/qurantxt/quran-simple-clean.json';
        if (identifier === 'quran-uthmani') return 'https://storage.googleapis.com/qurantxt/quran-uthmani.json';
        if (identifier === 'quran-uthmani-simple') return 'https://storage.googleapis.com/qurantxt/quran-uthmani.json';
        if (sourceApi === 'manual' || identifier.startsWith('http')) return identifier;
        if (sourceApi === 'fawazahmed0') return `https://cdn.jsdelivr.net/gh/fawazahmed0/quran-api@1/editions/${identifier}.json`;
        return `https://api.alquran.cloud/v1/quran/${identifier}`;
    }, []);

    const processApiData = (apiData: any, urlForTypeCheck: string): SurahData[] => {
        // Step 1: Normalize the API response into a consistent SurahData[] structure
        if (urlForTypeCheck.includes('fawazahmed0')) {
            return (apiData.quran || []).map((surah: any) => ({ ...surah, ayahs: (surah.verses || []).map((verse: any) => ({ ...verse, numberInSurah: verse.id, number: -1 /* Placeholder */ })) }));
        }
        if (apiData.code === 200 && apiData.data && apiData.data.surahs) {
            return apiData.data.surahs;
        }
        if (apiData.code === 200 && apiData.data && apiData.data.ayahs) {
            const surahsMap: { [key: number]: SurahData } = {};
            for (const ayah of apiData.data.ayahs) {
                if (!surahsMap[ayah.surah.number]) {
                    surahsMap[ayah.surah.number] = { ...ayah.surah, ayahs: [] };
                }
                surahsMap[ayah.surah.number].ayahs.push(ayah);
            }
            return Object.values(surahsMap).sort((a, b) => a.number - b.number);
        }

        throw new Error('Invalid or unexpected API data structure');
    };

    const fetchCustomEditionData = useCallback(async (editionIdentifier: string) => {
        let alreadyExistsOrLoading = false;
        setAllQuranData(prev => {
            if (prev && prev[editionIdentifier]) {
                alreadyExistsOrLoading = true;
            }
            return prev;
        });
        setLoadingEditions(prev => {
            if (prev.includes(editionIdentifier)) {
                alreadyExistsOrLoading = true;
            }
            return prev;
        });

        if (!editionIdentifier || alreadyExistsOrLoading) return;

        if (editionIdentifier === 'quran-uthmani-simple') {
            setAllQuranData(prev => {
                if (prev && !prev['quran-uthmani']) {
                    fetchCustomEditionDataRef.current('quran-uthmani');
                }
                return prev;
            });
            return;
        }

        setLoadingEditions(prev => [...prev, editionIdentifier]);
        setError(null);
        const isCoreEdition = editionIdentifier === 'quran-simple-clean' || editionIdentifier === 'quran-uthmani';

        const editionToFetch = availableEditions.find(e => e.identifier === editionIdentifier) || { identifier: editionIdentifier, sourceApi: 'manual' } as QuranEdition;
        if (!editionToFetch) {
            console.warn(`Edition ${editionIdentifier} not found in availableEditions.`);
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
            return;
        }

        const url = getEditionUrl(editionToFetch);

        try {
            const response = await fetch(url);
            if (!response.ok) throw new Error(`Network response was not ok: ${response.statusText}`);
            const apiData = await response.json();
            const surahs = processApiData(apiData, url);
            setAllQuranData(prev => ({ ...prev, [editionIdentifier]: surahs }));
        } catch (err) {
            console.error(`Failed to fetch edition ${editionIdentifier}:`, err);
            if (isCoreEdition) setError(`فشل تحميل بيانات المصحف الأساسية. قد تكون هناك مشكلة في الاتصال بالإنترنت.`);
        } finally {
            setLoadingEditions(prev => prev.filter(id => id !== editionIdentifier));
        }
    }, [availableEditions, getEditionUrl]);

    const fetchCustomEditionDataRef = useRef(fetchCustomEditionData);
    useEffect(() => {
        fetchCustomEditionDataRef.current = fetchCustomEditionData;
    }, [fetchCustomEditionData]);

    useEffect(() => {
        setAllQuranData(currentData => {
            if (currentData && currentData['quran-uthmani'] && !currentData['quran-uthmani-simple']) {
                const baseUthmaniData = currentData['quran-uthmani'];
                const processedSurahs: SurahData[] = baseUthmaniData.map((surah: any) => ({
                    ...surah,
                    ayahs: surah.ayahs.map((ayah: any) => ({ ...ayah, text: removeWaqfMarks(ayah.text) }))
                }));
                return { ...currentData, 'quran-uthmani-simple': processedSurahs };
            }
            return currentData;
        });
    }, [allQuranData]);

    useEffect(() => {
        const initializeApp = async () => {
            setIsInitialLoading(true);
            await fetchCustomEditionDataRef.current('quran-simple-clean');
            setIsInitialLoading(false);

            setIsBackgroundLoading(true);
            try {
                await Promise.all([
                    fetchCustomEditionDataRef.current('quran-uthmani'),
                    (async () => {
                        const fontsSnapshot = await db.collection('qran_fonts').get();
                        if (!fontsSnapshot.empty) setAvailableFonts(fontsSnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() })));
                    })(),
                    (async () => {
                        let apiEditions: QuranEdition[] = [];
                        try {
                            const response = await fetch('https://api.alquran.cloud/v1/edition');
                            if (response.ok) {
                                const data = await response.json();
                                if (data.code === 200 && Array.isArray(data.data)) {
                                    apiEditions = data.data.map((e: any) => ({
                                        identifier: e.identifier, language: e.language, name: e.name, englishName: e.englishName,
                                        format: e.format, type: e.type, direction: e.direction || (e.language === 'ar' ? 'rtl' : 'ltr'), sourceApi: 'alquran.cloud'
                                    }));
                                }
                            }
                        } catch (e) { console.warn("Could not fetch from alquran.cloud API", e); }

                        let firestoreEditions: QuranEdition[] = [];
                        try {
                            const editionsSnapshot = await db.collection('qran_editions').get();
                            if (!editionsSnapshot.empty) firestoreEditions = editionsSnapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() }));
                        } catch (e) { console.warn("Could not fetch from Firestore 'qran_editions'", e); }

                        const editionMap = new Map<string, QuranEdition>();
                        [...apiEditions, ...firestoreEditions, ...FULL_DEFAULT_EDITIONS].forEach(e => editionMap.set(e.identifier, e));
                        setAvailableEditions(Array.from(editionMap.values()));
                    })(),
                ]);
            } catch (err) {
                console.error("Error during background initialization:", err);
            } finally {
                setIsBackgroundLoading(false);
            }
        };
        initializeApp();
    }, []); // Empty dependency array ensures this effect runs only once on mount.

    useEffect(() => {
        availableFonts.forEach(font => {
            if (font.url && !document.querySelector(`link[href="${font.url}"]`)) {
                const link = document.createElement('link');
                link.href = font.url;
                link.rel = 'stylesheet';
                document.head.appendChild(link);
            }
        });
    }, [availableFonts]);

    return {
        allQuranData, isInitialLoading, isBackgroundLoading, loadingEditions, error,
        dataSourceStatus, availableFonts, availableEditions,
        fetchCustomEditionData, getEditionUrl,
    };
};

